export interface Article {
  slug: string;
  title: string;
  category: CategoryId;
  excerpt: string;
  readTime: number;
  date: string;
  author: string;
  featured?: boolean;
  sections: ArticleSection[];
}

export interface ArticleSection {
  heading: string;
  content: string;
  callout?: { type: "info" | "warning"; text: string };
}

export type CategoryId =
  | "types-of-debt"
  | "tax-debt"
  | "bankruptcy"
  | "debt-settlement"
  | "cash-flow"
  | "know-your-rights"
  | "industry-guides";

export interface Category {
  id: CategoryId;
  label: string;
  description: string;
}

export const categories: Category[] = [
  { id: "types-of-debt", label: "Types of Business Debt", description: "Understanding the specific risks and mechanics of every common business debt type." },
  { id: "tax-debt", label: "Tax Debt", description: "IRS and state tax obligations, penalties, and resolution strategies for business owners." },
  { id: "bankruptcy", label: "Bankruptcy", description: "Chapter 7, Chapter 11, Subchapter V, and alternatives to federal bankruptcy filing." },
  { id: "debt-settlement", label: "Debt Settlement & Negotiation", description: "Strategies for negotiating with creditors, settling debts, and restructuring payment terms." },
  { id: "cash-flow", label: "Cash Flow & Turnaround", description: "Stabilizing cash flow, prioritizing payments, and rebuilding after financial distress." },
  { id: "know-your-rights", label: "Know Your Rights", description: "Legal protections, statute of limitations, and defenses available to business debtors." },
  { id: "industry-guides", label: "Industry Guides", description: "Sector-specific debt challenges and tailored strategies for different business types." },
];

export const getCategoryLabel = (id: CategoryId): string =>
  categories.find((c) => c.id === id)?.label ?? id;

const a = (
  slug: string,
  title: string,
  category: CategoryId,
  excerpt: string,
  readTime: number,
  date: string,
  sections: ArticleSection[],
  featured = false
): Article => ({
  slug,
  title,
  category,
  excerpt,
  readTime,
  date,
  author: "Editorial Team",
  featured,
  sections,
});

export const articles: Article[] = [
  // ── TYPES OF DEBT ──────────────────────────────────────────
  a("merchant-cash-advances-explained", "Merchant Cash Advances Explained: How Daily ACH Debits Create a Debt Spiral", "types-of-debt",
    "MCAs promise fast capital, but daily ACH debits and triple-digit effective APRs can trap businesses in a cycle of borrowing that's nearly impossible to escape.",
    12, "2025-11-15", [
      { heading: "What Is a Merchant Cash Advance?", content: "A merchant cash advance is not technically a loan — it's a purchase of future receivables at a discount. An MCA provider advances a lump sum to a business in exchange for a percentage of future daily credit card sales or fixed daily ACH debits from the business's bank account. Because MCAs aren't classified as loans in most states, they fall outside traditional lending regulations, including usury caps.\n\nThe cost is expressed as a \"factor rate\" rather than an interest rate. A typical factor rate of 1.3 to 1.5 means a business that receives $100,000 will repay $130,000 to $150,000 — regardless of how long repayment takes. When the repayment term is compressed into 3–6 months of daily debits, the effective APR can exceed 200%." },
      { heading: "How Daily ACH Debits Drain Cash Flow", content: "Unlike monthly loan payments that businesses can plan around, MCA debits hit your bank account every business day. A $100,000 advance with a 1.4 factor rate and 6-month term means daily debits of approximately $1,167. That's $5,833 per week leaving your operating account before you pay rent, payroll, or vendors.\n\nThe daily debit structure creates a particularly dangerous dynamic: when revenue dips, the fixed daily withdrawal represents a larger percentage of available cash. This often forces business owners to seek additional advances to cover the shortfall — the beginning of the debt spiral.", callout: { type: "warning", text: "The most dangerous aspect of MCAs is \"stacking\" — taking a second or third advance to cover the payments on the first. Each new advance has its own daily debit, compounding the cash drain exponentially." } },
      { heading: "The Stacking Trap", content: "MCA stacking occurs when a business takes multiple advances from different providers simultaneously. Each provider debits the bank account daily, and the combined withdrawals can exceed 30–50% of daily revenue. Because MCA providers share position information through platforms like the UCC filing system, later-position funders charge even higher factor rates to compensate for increased risk.\n\nA business that starts with one $50,000 advance at a 1.35 factor rate might end up with three advances totaling $200,000 in principal but owing $320,000 in total repayment — with combined daily debits of $3,000 or more." },
      { heading: "Legal Considerations", content: "Because MCAs are structured as commercial transactions rather than loans, they're largely unregulated. However, some states are beginning to impose disclosure requirements. New York's Commercial Finance Disclosure Law, for example, now requires MCA providers to disclose the estimated APR equivalent of their products.\n\nSome MCA agreements contain confessions of judgment (COJ), which allow the funder to obtain a court judgment against the business without notice or a hearing. While New York banned out-of-state COJs in 2019, they remain enforceable in many jurisdictions." },
      { heading: "What to Do If You're Stuck", content: "If your business is trapped in an MCA debt spiral, options include: revoking ACH authorization (though this triggers default), negotiating a restructured payment plan, consolidating multiple MCAs into a single manageable payment, or in severe cases, filing for Chapter 11 bankruptcy protection, which immediately stops all ACH debits through the automatic stay.\n\nThe key is acting before your bank account is levied. Once an MCA company obtains a confession of judgment and freezes your account, your options become much more limited." },
    ], true),

  a("sba-loan-default", "SBA Loan Default: What Happens When You Can't Pay Your 7(a) or EIDL Loan", "types-of-debt",
    "SBA loans come with personal guarantees and the full collection power of the federal government. Here's what default actually looks like.",
    10, "2025-10-28", [
      { heading: "Understanding SBA Loan Guarantees", content: "When you take an SBA 7(a) loan, the SBA guarantees 75–85% of the loan to the lender. But you personally guarantee 100% of the loan to the SBA. Every owner with 20% or more ownership must sign a personal guarantee, and the SBA requires collateral including personal assets when business assets are insufficient.\n\nThis creates a unique dynamic: the lender has relatively low risk, the SBA bears moderate risk, and you — the borrower — bear the most risk of all." },
      { heading: "The Default Timeline", content: "When you miss payments, the lender typically sends notices for 60–90 days before declaring default. The lender then attempts to liquidate collateral and collect from guarantors. If the lender can't recover the full balance, it files a claim with the SBA for the guaranteed portion.\n\nOnce the SBA pays the lender's claim, the SBA becomes your creditor — and the federal government has collection tools that no private lender can match." },
      { heading: "Treasury Offset Program", content: "The SBA refers uncollected debt to the Treasury Department, which can intercept federal payments owed to you: tax refunds, Social Security benefits, federal salary payments, and federal contractor payments. This happens automatically through the Treasury Offset Program and can continue for decades.", callout: { type: "warning", text: "Unlike private debt, SBA debt has no statute of limitations for federal collection. The government can pursue you indefinitely." } },
      { heading: "EIDL Loan Specifics", content: "COVID-era EIDL loans created unique challenges. Many businesses received $150,000+ in EIDL funds with 30-year repayment terms. While the first 30 months were payment-free, many businesses spent the funds on operating expenses that didn't generate lasting revenue.\n\nEIDL loans under $200,000 don't require personal guarantees, but the SBA still has a security interest in all business assets. Loans over $200,000 require personal guarantees and real estate collateral." },
      { heading: "Resolution Options", content: "The SBA offers several resolution paths: Offer in Compromise (settling for less than the full balance), installment agreements, and in some cases, hardship discharge. The SBA's OIC program considers your ability to pay, asset equity, income, and expenses.\n\nBankruptcy can discharge SBA debt, but the personal guarantee makes it critical to address both the business and personal liability. Chapter 11 reorganization can restructure SBA payments while keeping the business operating." },
    ], true),

  a("hidden-danger-stacking-mcas", "The Hidden Danger of Stacking Multiple MCAs", "types-of-debt",
    "When one MCA isn't enough to cover the last one, businesses enter a dangerous cycle. Here's how stacking works and why it's so destructive.",
    8, "2025-10-15", [
      { heading: "What Is MCA Stacking?", content: "MCA stacking occurs when a business has multiple merchant cash advances from different funders simultaneously. Because MCA providers can check UCC filings to see existing positions, they know when a business already has an advance — and they fund anyway, at higher factor rates.\n\nA business might start with one $50,000 advance, then take a second $30,000 advance to cover the daily debits from the first, then a third to cover both. Within months, the business can owe $200,000+ with daily ACH debits exceeding $3,000." },
      { heading: "How Factor Rates Escalate", content: "First-position MCAs might offer factor rates of 1.25 to 1.35. Second-position funders, knowing they're behind another creditor, charge 1.40 to 1.50. Third-position rates can exceed 1.50 — meaning you repay $150,000 on a $100,000 advance within a few months.\n\nThe combined cost of stacked MCAs can produce effective annual percentage rates exceeding 400%. No legitimate business can sustain that cost of capital." },
      { heading: "The Math of Destruction", content: "Consider a real scenario: A restaurant takes a $75,000 first-position MCA at 1.35, owing $101,250 over 6 months ($843/day). Three months in, cash is tight, so they take a $40,000 second-position at 1.45, owing $58,000 over 4 months ($725/day). Now paying $1,568/day.\n\nTwo months later, they take a $25,000 third-position at 1.50 — owing $37,500 over 3 months ($625/day). Total daily debits: $2,193. That's $10,965/week leaving the bank account before a single employee is paid.", callout: { type: "info", text: "The total cost of capital in this scenario exceeds $56,750 on $140,000 borrowed — and the repayment timeline is so compressed that the effective APR exceeds 300%." } },
      { heading: "Breaking the Cycle", content: "Options for escaping MCA stacking include: negotiating a consolidated repayment plan with all funders, opening a new bank account to interrupt ACH debits (which triggers default but buys time), filing for Chapter 11 or Subchapter V bankruptcy, or negotiating individual settlements if you can access a lump sum.\n\nThe critical first step is stopping the bleeding — you cannot negotiate effectively while daily debits continue draining your account." },
    ]),

  a("equipment-financing-default", "Equipment Financing & Leases: What Happens When You Default", "types-of-debt",
    "Equipment loans and leases carry specific risks including repossession, deficiency balances, and personal liability.",
    7, "2025-09-20", [
      { heading: "Equipment Loans vs. Equipment Leases", content: "Equipment loans are secured by the equipment itself — similar to a car loan. You own the equipment and build equity as you pay. Equipment leases, by contrast, may be true leases (you return the equipment) or capital leases (you own it at the end). The distinction matters enormously in default.\n\nFair market value leases give you the option to buy at the end but don't obligate you. $1 buyout leases are essentially financing arrangements classified as leases." },
      { heading: "The Deficiency Balance Problem", content: "When a lender repossesses equipment, they sell it — usually at auction for a fraction of retail value. The difference between the sale price and your outstanding balance is the deficiency balance, and you still owe it.\n\nA $200,000 piece of construction equipment might sell at auction for $80,000, leaving you with a $120,000 deficiency balance — plus repossession costs, storage fees, and auction commissions. If you personally guaranteed the equipment loan, that deficiency becomes your personal debt.", callout: { type: "warning", text: "Voluntary surrender doesn't eliminate the deficiency balance. You still owe the difference between what the equipment sells for and what you owed." } },
      { heading: "Lease Termination Penalties", content: "Early lease termination typically triggers a penalty equal to all remaining lease payments. A 5-year equipment lease with 3 years remaining could generate a termination penalty exceeding the equipment's current market value.\n\nSome leases are explicitly non-cancelable and survive even bankruptcy filing. Understanding your lease terms before default is critical." },
      { heading: "Strategic Options", content: "Options include: negotiating a voluntary surrender with a waiver of deficiency balance, requesting a loan modification with extended terms, refinancing the equipment loan at lower payments, or including the equipment debt in a Chapter 11 reorganization plan that may allow you to retain the equipment at fair market value (the \"cramdown\" provision)." },
    ]),

  a("business-credit-card-personal-liability", "Business Credit Card Debt: When Personal Liability Becomes Real", "types-of-debt",
    "Most business credit cards make the owner personally liable. Here's what that means for your personal credit and assets.",
    6, "2025-09-05", [
      { heading: "The Personal Liability Trap", content: "Despite the name, most business credit cards require a personal guarantee from the owner. Unlike consumer credit cards, business cards aren't covered by the same protections under the CARD Act. Issuers can raise rates, change terms, and reduce credit limits with minimal notice.\n\nWhen a business defaults on its credit cards, the issuer pursues the personal guarantor — which means lawsuits, wage garnishment, and damage to your personal credit score." },
      { heading: "Impact on Personal Credit", content: "Some business card issuers report to personal credit bureaus, while others report only to business credit agencies. When an account goes delinquent, however, nearly all issuers report the negative information to personal credit bureaus.\n\nA charged-off business credit card can drop your personal credit score by 100+ points and remain on your credit report for seven years." },
      { heading: "Protecting Yourself", content: "While you can't retroactively remove a personal guarantee, you can: negotiate a settlement for less than the full balance (typically 40–60% for charged-off accounts), set up a hardship payment plan, include the debt in a personal bankruptcy filing, or dispute inaccurate reporting on your personal credit report.\n\nPrevention is key: consider cards from issuers that don't report to personal bureaus, and maintain separate personal and business credit profiles." },
    ]),

  a("revenue-based-financing-risks", "Revenue-Based Financing vs. Traditional Loans: Risks Compared", "types-of-debt",
    "Revenue-based financing promises flexibility but often carries hidden dangers, including confessions of judgment and aggressive collection.",
    7, "2025-08-22", [
      { heading: "How Revenue-Based Financing Works", content: "Revenue-based financing (RBF) provides capital in exchange for a percentage of future revenue. Unlike MCAs with fixed daily debits, RBF payments theoretically adjust with your revenue — you pay more when business is good and less when it's slow.\n\nIn practice, many RBF agreements have minimum payment floors, meaning the \"flexible\" payments aren't as flexible as advertised. Some also have maturity dates that trigger balloon payments." },
      { heading: "Hidden Contractual Risks", content: "Many RBF agreements contain provisions that look innocuous but create serious risk: confession of judgment clauses, broad personal guarantees that extend beyond the business entity, cross-default provisions that trigger default if you're late on any other obligation, and UCC-1 filings that create a blanket lien on all business assets.\n\nThe most dangerous provision is the confession of judgment, which allows the lender to obtain a court judgment against you without notice, hearing, or opportunity to contest the claim." },
      { heading: "Comparing Costs", content: "RBF typically costs 20–40% of the funded amount over a 12–18 month period, translating to effective APRs of 20–60%. While cheaper than MCAs, this is significantly more expensive than traditional bank financing (typically 5–15% APR).\n\nThe cost comparison becomes even more unfavorable when you factor in origination fees, late fees, and the compound cost of refinancing when the initial term expires." },
      { heading: "When RBF Makes Sense — and When It Doesn't", content: "RBF can work for businesses with predictable, growing revenue that need short-term capital for a specific growth opportunity. It doesn't work for businesses using it to cover operating shortfalls — that's the beginning of a debt spiral.\n\nBefore accepting any RBF offer, have an attorney review the contract terms, particularly the confession of judgment, personal guarantee, and default provisions." },
    ]),

  a("understanding-ucc-liens", "Understanding UCC Liens and How They Affect Your Business", "types-of-debt",
    "A UCC filing gives creditors a security interest in your business assets. Here's what that means and how to deal with it.",
    8, "2025-08-10", [
      { heading: "What Is a UCC Lien?", content: "A UCC-1 financing statement is a legal form filed with the Secretary of State that establishes a creditor's security interest in your business assets. It puts other potential lenders on notice that the filer has a claim on your property.\n\nUCC liens can be specific (attached to particular equipment) or blanket (covering all business assets, including accounts receivable, inventory, and equipment). Most MCA funders and alternative lenders file blanket UCC-1 liens." },
      { heading: "How UCC Liens Affect Your Business", content: "A UCC filing doesn't take your property — but it severely limits what you can do with it. Other lenders will see the filing and may refuse to extend credit. If you try to sell assets covered by the lien, the buyer takes them subject to the lien (meaning the creditor can repossess them from the buyer).\n\nMultiple UCC filings create a priority system: the first to file has priority over later filers. This is why second and third-position MCA funders charge higher rates — they know they're behind other creditors.", callout: { type: "info", text: "UCC filings are public records. You can search for liens filed against your business through your state's Secretary of State website." } },
      { heading: "Removing UCC Liens", content: "UCC-1 filings automatically expire after 5 years unless the creditor files a continuation statement. If you've paid off the debt, the creditor is required to file a UCC-3 termination statement within 20 days of your written demand.\n\nIf a creditor fails to terminate after demand, you may have legal claims for damages under UCC Article 9. In some states, you can file an authorized termination statement yourself if the secured party is unresponsive." },
    ]),

  a("confession-of-judgment", "Confession of Judgment: The Most Dangerous Clause in Your Loan Agreement", "types-of-debt",
    "A COJ lets a lender get a court judgment against you without notice. Here's how it works and what protections exist.",
    7, "2025-07-28", [
      { heading: "What Is a Confession of Judgment?", content: "A confession of judgment (COJ) is a clause in a contract where the borrower agrees in advance to let the lender obtain a court judgment without the normal litigation process. If you default, the lender files the COJ with the court and immediately receives a judgment — no lawsuit, no hearing, no chance to argue your case.\n\nWith a judgment in hand, the lender can immediately levy your bank accounts, garnish wages, and seize assets." },
      { heading: "The New York Problem", content: "New York has historically been the favored jurisdiction for COJ enforcement because its courts processed them quickly and efficiently. MCA funders often included New York venue clauses in contracts with businesses across the country.\n\nIn 2019, New York banned the enforcement of COJs against out-of-state borrowers and imposed new filing requirements for in-state COJs. This was a major victory for small businesses, but COJs remain enforceable in many other states." },
      { heading: "Fighting a Confession of Judgment", content: "Even after a COJ judgment is entered, you may be able to vacate it if: the underlying contract was fraudulent or unconscionable, the COJ was obtained through fraud or misrepresentation, the court lacked jurisdiction, the creditor materially breached the agreement first, or the judgment amount is incorrect.\n\nAn emergency motion to vacate, combined with a motion to quash any bank levies, should be filed immediately upon discovering that a COJ judgment has been entered." },
    ]),

  a("commercial-real-estate-default", "Commercial Real Estate Loans: Recourse vs Non-Recourse and What Default Looks Like", "types-of-debt",
    "Commercial mortgage default is faster and less forgiving than residential. Understanding recourse liability is critical.",
    8, "2025-07-15", [
      { heading: "Commercial vs. Residential Default", content: "Commercial foreclosure is a fundamentally different process than residential foreclosure. There are fewer borrower protections, shorter timelines, and the lender typically has more leverage. Most commercial loans have terms of 5–10 years with 25–30 year amortization, creating balloon payment risk at maturity.\n\nCommercial borrowers don't benefit from the same consumer protection laws that provide residential borrowers with extensive notice requirements, mediation programs, and foreclosure alternatives." },
      { heading: "Recourse vs. Non-Recourse", content: "A recourse loan allows the lender to pursue your personal assets if the property sale doesn't cover the full debt. A non-recourse loan limits the lender's recovery to the property itself — in theory.\n\nIn practice, non-recourse loans contain \"bad boy\" carve-outs that make the loan fully recourse if certain events occur: filing bankruptcy, committing fraud, transferring the property without consent, failing to maintain insurance, or allowing environmental contamination. These carve-outs are broadly written and frequently triggered.", callout: { type: "warning", text: "\"Non-recourse\" doesn't mean \"no personal liability.\" Bad boy carve-outs in most commercial loan documents can convert a non-recourse loan to full recourse." } },
      { heading: "Default Strategies", content: "Options include: loan modification (extending the maturity, reducing the rate), deed in lieu of foreclosure (transferring the property to avoid a public foreclosure), negotiated sale (selling the property and negotiating forgiveness of any deficiency), or Chapter 11 reorganization (which can force a restructured payment plan on the lender under certain conditions).\n\nThe worst option is usually doing nothing — commercial lenders move quickly and the costs of foreclosure (receiver fees, attorney fees, property deterioration) reduce the ultimate recovery for everyone." },
    ]),

  a("factoring-invoice-financing", "Factoring & Invoice Financing: What Your Customers Don't Know Can Hurt You", "types-of-debt",
    "Factoring converts receivables to cash but can damage customer relationships and create hidden liability.",
    7, "2025-07-01", [
      { heading: "How Factoring Works", content: "Invoice factoring involves selling your accounts receivable to a factoring company at a discount. The factor advances you 80–90% of the invoice value immediately, then collects the full amount from your customer. When the customer pays, you receive the remaining balance minus the factor's fee.\n\nFactoring fees typically range from 1–5% per month, which can translate to annual costs of 12–60% depending on how quickly your customers pay." },
      { heading: "Notification vs. Non-Notification Factoring", content: "Notification factoring means the factor contacts your customers directly and instructs them to redirect payments. This alerts customers to your financial situation, which can damage relationships and create concern about your business's stability.\n\nNon-notification factoring is more discreet — payments still come to you, and you forward them to the factor. However, non-notification arrangements are more expensive and may contain tighter covenants." },
      { heading: "Recourse Provisions", content: "In recourse factoring, if your customer doesn't pay the invoice, you're required to buy it back or replace it with a collectible invoice. This means the factor's risk is limited while you retain the credit risk.\n\nNon-recourse factoring (where the factor absorbs the credit risk) is more expensive and typically only covers customer insolvency — not payment disputes. If a customer refuses to pay due to a quality complaint, you still owe the factor." },
    ]),

  a("vendor-credit-trade-debt", "Vendor Credit and Trade Debt: What Happens When Suppliers Cut You Off", "types-of-debt",
    "Losing vendor terms creates a cascading crisis. Here's what happens and how to manage it.",
    6, "2025-06-18", [
      { heading: "The Vendor Credit Lifeline", content: "Trade credit — the ability to receive goods and pay 30, 60, or 90 days later — is one of the most important forms of business financing. It's interest-free, relationship-based, and often represents hundreds of thousands of dollars in de facto financing.\n\nWhen vendors pull trade credit and put you on COD (cash on delivery) or CIA (cash in advance), the cash flow impact can be devastating. You now need cash upfront for supplies you previously paid for 30–60 days later." },
      { heading: "When Vendors Sue", content: "Vendor lawsuits for unpaid invoices are common and can be aggressive. Suppliers may file mechanic's liens (in construction), obtain prejudgment attachments, or pursue personal guarantees. A judgment gives the vendor access to bank levies, asset seizure, and wage garnishment.\n\nMultiple vendor lawsuits can quickly overwhelm a business's ability to operate, as legal costs mount and bank accounts are frozen by competing levies." },
      { heading: "Rebuilding Vendor Relationships", content: "If your business is viable, vendors generally prefer to work with you rather than pursue collection — an ongoing customer is worth more than a lawsuit recovery. The key is proactive, honest communication: acknowledge the problem, propose realistic payment terms, make every promised payment on time, and gradually rebuild trust.\n\nStart by prioritizing vendors who are essential to your operations and those most likely to work with you. Consider offering secured payment terms or smaller, more frequent payments to demonstrate reliability." },
    ]),

  // ── TAX DEBT ──────────────────────────────────────────
  a("payroll-tax-debt-941", "Payroll Tax Debt (941): Why the IRS Holds Business Owners Personally Liable", "tax-debt",
    "Unpaid payroll taxes are among the most dangerous business debts. The Trust Fund Recovery Penalty makes owners personally liable.",
    10, "2025-11-10", [
      { heading: "Why Payroll Taxes Are Different", content: "When you withhold income taxes and FICA from employee paychecks, that money belongs to the government — you're simply holding it in trust. When you fail to remit it, the IRS views this as the equivalent of theft. The taxes you failed to pay are called \"trust fund taxes\" because they were held in trust for the government.\n\nThis is fundamentally different from income tax debt. Income tax is your obligation to the government. Trust fund taxes are your employees' money that you were supposed to forward to the government. This distinction drives the aggressive collection treatment." },
      { heading: "The Trust Fund Recovery Penalty (TFRP)", content: "The IRS can assess the Trust Fund Recovery Penalty against any \"responsible person\" who willfully failed to pay trust fund taxes. This is a personal assessment — it attaches to the individual, not the business entity.\n\nA \"responsible person\" includes anyone with authority over the business's financial decisions: owners, officers, directors, and even bookkeepers or accountants with check-signing authority. The IRS often assesses the TFRP against multiple individuals simultaneously.", callout: { type: "warning", text: "The TFRP equals 100% of the unpaid trust fund portion. If your business owes $100,000 in payroll taxes, approximately $70,000 may be trust fund — and each responsible person can be assessed that full $70,000 individually." } },
      { heading: "How the IRS Collects", content: "The IRS has extraordinary collection powers: filing tax liens on all your property, levying bank accounts and wages, seizing assets, and revoking your passport for seriously delinquent tax debt (over $62,000). Unlike private creditors, the IRS doesn't need a court order to levy your bank account.\n\nThe IRS also has 10 years from the date of assessment to collect — the Collection Statute Expiration Date (CSED). While 10 years might seem like a limit, IRS collection actions can extend the CSED through various tolling events." },
      { heading: "Resolution Paths", content: "Options include: Installment Agreement (spreading payments over up to 72 months), Offer in Compromise (settling for less than owed), Currently Not Collectible status (temporary halt to collection if you can't pay basic expenses), or penalty abatement (removing failure-to-deposit and failure-to-pay penalties).\n\nFor current businesses, the IRS requires that all current payroll tax deposits be made on time as a condition of any resolution agreement. You cannot negotiate past-due taxes while continuing to fall behind on current obligations." },
    ], true),

  a("trust-fund-recovery-penalty", "The Trust Fund Recovery Penalty: How the IRS Comes After You Personally", "tax-debt",
    "The TFRP can make individual business owners liable for 100% of unpaid employee withholding taxes.",
    8, "2025-10-22", [
      { heading: "Who Is a 'Responsible Person'?", content: "The IRS defines a responsible person broadly: anyone who had the duty to collect, account for, and pay over trust fund taxes, and who had the authority to direct the payment of creditors. This typically includes business owners, officers, and directors, but can extend to controllers, bookkeepers, payroll service providers, and even lenders who exercise control over the business's finances.\n\nImportantly, more than one person can be held liable. The IRS often assesses the TFRP against multiple individuals and lets them fight over contribution among themselves." },
      { heading: "What 'Willfulness' Means", content: "Willfulness doesn't require evil intent — it simply means the responsible person knew about the tax obligation and voluntarily, consciously, and intentionally chose to pay other creditors instead of the IRS. Paying rent, payroll, or vendors before payroll taxes constitutes willfulness.\n\nThe only defense is showing that you had no authority over financial decisions or that you didn't know about the unpaid taxes. Both defenses are difficult to establish, especially for business owners." },
      { heading: "The Assessment Process", content: "The IRS conducts a Trust Fund Recovery Penalty investigation using Form 4180. A Revenue Officer interviews each potential responsible person, asking detailed questions about their role, authority, and knowledge of the tax delinquency.\n\nAfter the investigation, the IRS proposes the TFRP assessment and gives you 60 days to appeal. If you don't appeal, the assessment becomes final and the IRS begins collection — filing liens, levying bank accounts, and garnishing wages." },
    ]),

  a("state-sales-tax-debt", "State Sales Tax Debt: Officer Liability and Aggressive Collection Tactics", "tax-debt",
    "States are increasingly aggressive in collecting unpaid sales tax, and officers can be held personally liable.",
    7, "2025-10-08", [
      { heading: "Sales Tax as Trust Fund Obligation", content: "Like payroll taxes, sales tax collected from customers is considered trust fund money — you collected it on behalf of the state and are legally required to remit it. Failure to do so is treated as conversion of state property.\n\nEvery state with a sales tax imposes personal liability on \"responsible officers\" — typically defined as anyone with authority to collect, manage, or direct the remittance of sales tax. This includes owners, officers, directors, managers, and sometimes partners." },
      { heading: "State Collection Powers", content: "State tax agencies have broad collection authority: filing tax warrants (equivalent to judgments), levying bank accounts, garnishing wages, seizing business equipment, revoking business licenses, and in extreme cases, closing the business. Some states can also revoke professional licenses and driver's licenses for unpaid taxes.\n\nMany states are more aggressive than the IRS because they have fewer taxpayers to manage and more political pressure to collect. Response times to collection notices are often shorter, and payment plan options may be more limited." },
      { heading: "Resolution Options", content: "Most states offer installment agreements, though the terms vary widely. Some states have Offer in Compromise programs similar to the IRS, while others have no settlement authority and require payment in full. Penalty abatement is available in most states for reasonable cause.\n\nThe most critical action is becoming compliant with current filing and payment obligations. States will not negotiate past-due balances while new liabilities are accumulating." },
    ]),

  a("irs-offer-in-compromise", "IRS Offer in Compromise for Business Tax Debt: A Complete Guide", "tax-debt",
    "The OIC program can settle tax debt for less than owed, but qualifying requires meeting strict financial criteria.",
    9, "2025-09-15", [
      { heading: "What Is an Offer in Compromise?", content: "An Offer in Compromise allows you to settle your tax debt with the IRS for less than the full amount owed. The IRS accepts an OIC when the amount offered represents the most the IRS can expect to collect within a reasonable period. There are three grounds: doubt as to collectibility (most common), doubt as to liability, and effective tax administration.\n\nFor business tax debt, doubt as to collectibility is the primary basis — you demonstrate that your assets, income, and future earning capacity can't satisfy the full tax debt within the remaining collection statute." },
      { heading: "How the IRS Calculates Your Offer", content: "The IRS uses a formula: Quick Sale Value of Assets + (Monthly Disposable Income × Future Income Multiplier). For a lump-sum offer (paid within 5 months), the multiplier is 12. For a periodic payment offer (paid over 6–24 months), the multiplier is 24.\n\nMonthly disposable income is your total income minus IRS-allowed expenses. The IRS has specific allowable expense standards for housing, transportation, food, and other necessities. If your actual expenses exceed these standards, you must justify the difference.", callout: { type: "info", text: "Before applying, you must be current on all filing obligations and current-year estimated tax payments. The IRS will reject any OIC from a non-compliant taxpayer." } },
      { heading: "The Application Process", content: "Submit Form 656 (Offer in Compromise) along with Form 433-A (for individuals) or Form 433-B (for businesses), detailed financial documentation, and a $205 application fee. Low-income taxpayers may qualify for a fee waiver.\n\nFor lump-sum offers, include 20% of the total offer amount with the application. For periodic payment offers, begin making proposed payments while the offer is being considered. Processing typically takes 6–12 months." },
      { heading: "After Acceptance", content: "If accepted, you must comply with all tax filing and payment obligations for the next 5 years. Any failure to comply during this period can result in default of the offer, reinstatement of the original debt (minus payments made), and loss of the right to contest the original amount.\n\nYou must also report any significant increase in income or assets to the IRS during the compliance period, as this could trigger a review of the offer terms." },
    ]),

  a("installment-agreements-business-tax", "Installment Agreements for Business Tax Debt: Regular vs Partial-Pay Options", "tax-debt",
    "The IRS offers several installment plan types for business tax debt, each with different requirements and implications.",
    7, "2025-09-01", [
      { heading: "Types of Installment Agreements", content: "The IRS offers several types: Guaranteed (for debts under $10,000), Streamlined (for debts under $25,000 for individuals or $25,000 for businesses), and Non-Streamlined (for larger amounts requiring detailed financial disclosure).\n\nFor businesses, the streamlined threshold is lower, and the IRS requires that the balance be paid within 24 months or before the Collection Statute Expiration Date, whichever is sooner." },
      { heading: "Partial-Pay Installment Agreements", content: "A Partial-Pay Installment Agreement (PPIA) allows payments that won't fully satisfy the debt before the collection statute expires. The IRS accepts PPIAs when the taxpayer can't afford full-pay installments but can make some monthly payment.\n\nThe IRS reviews PPIAs every two years to determine if your financial situation has improved. If it has, the IRS may increase your payment amount. If it hasn't, the remaining balance may ultimately be written off when the CSED expires.", callout: { type: "info", text: "The Collection Statute Expiration Date (CSED) is 10 years from the date of assessment. If you can make partial payments until the CSED expires, the remaining balance is legally uncollectible." } },
      { heading: "Requirements and Compliance", content: "All installment agreements require current filing compliance and timely current-year tax payments. Failure to file a return or pay current taxes can default the agreement, reinstating full collection activity.\n\nThe IRS charges a setup fee ($225 for standard, $107 for direct debit, reduced fees for low-income taxpayers) and interest and penalties continue to accrue during the payment plan." },
    ]),

  a("currently-not-collectible", "Currently Not Collectible Status: Buying Time When You Can't Pay the IRS", "tax-debt",
    "CNC status temporarily halts IRS collection when paying would prevent you from meeting basic expenses.",
    6, "2025-08-18", [
      { heading: "What Is CNC Status?", content: "Currently Not Collectible is an IRS designation indicating that collecting the tax debt would create undue economic hardship. When your account is placed in CNC status, the IRS temporarily stops levies, wage garnishments, and other collection actions.\n\nCNC doesn't eliminate the debt — interest and penalties continue to accrue, and the IRS retains its tax lien. However, the collection statute continues to run, meaning the debt may eventually expire." },
      { heading: "Qualifying for CNC", content: "You must demonstrate that your monthly income is less than your monthly necessary living expenses using IRS-allowed expense standards. The IRS will require detailed financial documentation including bank statements, pay stubs, and proof of expenses.\n\nFor businesses, CNC may be appropriate when the business generates enough revenue to cover operating costs and current tax obligations but has no capacity to pay past-due balances." },
      { heading: "Strategic Use of CNC", content: "CNC can be a strategic tool when the collection statute is relatively short (e.g., 3–5 years remaining). If you can maintain CNC status until the CSED expires, the debt is legally eliminated without payment.\n\nHowever, the IRS reviews CNC accounts periodically and may resume collection if your financial situation improves. Any significant increase in income or acquisition of assets can trigger a review." },
    ]),

  a("tax-consequences-settled-debt", "Tax Consequences of Settled Business Debt: What You Owe After You Settle", "tax-debt",
    "When debt is forgiven, the IRS may consider it taxable income. Understanding the exceptions can save you thousands.",
    7, "2025-08-05", [
      { heading: "Cancellation of Debt Income", content: "When a creditor forgives more than $600 of debt, they're required to file Form 1099-C reporting the canceled amount. The IRS treats this canceled debt as taxable income — you owe tax on money you never actually received.\n\nFor example, if you settle a $200,000 business debt for $80,000, the creditor may issue a 1099-C for $120,000 in canceled debt. At a 30% effective tax rate, that's $36,000 in unexpected taxes." },
      { heading: "The Insolvency Exception", content: "You can exclude canceled debt from income to the extent you were insolvent immediately before the cancellation. Insolvency means your total liabilities exceeded your total assets. If you were insolvent by $120,000 or more, the entire canceled amount is excluded.\n\nYou must file Form 982 with your tax return to claim the insolvency exception. Calculating insolvency requires a detailed balance sheet listing all assets at fair market value and all liabilities — a task best handled by a CPA experienced in cancellation of debt issues.", callout: { type: "info", text: "The insolvency exception is calculated at the individual level, not the business level. Include all personal assets and liabilities, not just business ones." } },
      { heading: "Bankruptcy Exception", content: "Debt discharged through bankruptcy (Chapter 7, 11, or 13) is completely excluded from taxable income under IRC Section 108(a)(1)(A). This is an absolute exclusion — no insolvency calculation is needed.\n\nThis is one of the often-overlooked benefits of bankruptcy: it eliminates both the debt AND the tax liability on the forgiven amount." },
    ]),

  a("penalty-abatement-strategies", "Penalty Abatement Strategies: How to Reduce IRS Penalties Legally", "tax-debt",
    "IRS penalties can add 25%+ to your tax bill. Here are the legal strategies for getting them removed.",
    6, "2025-07-22", [
      { heading: "First-Time Penalty Abatement", content: "The IRS's First-Time Abate (FTA) policy removes failure-to-file and failure-to-pay penalties for taxpayers who have been compliant for the prior three years. You must have filed all required returns, paid or arranged to pay all tax due, and had no penalties assessed in the three preceding tax years.\n\nFTA can be requested by phone, letter, or through a tax professional. It's the easiest penalty relief to obtain and should always be considered first." },
      { heading: "Reasonable Cause", content: "If you don't qualify for FTA, you can request penalty abatement based on reasonable cause — circumstances beyond your control that prevented timely filing or payment. Acceptable reasons include: serious illness, natural disaster, death of a key person, fire or casualty, inability to obtain records, and erroneous IRS advice.\n\nSimply not having money to pay is generally NOT reasonable cause for failure-to-pay penalties. However, it can support an argument when combined with other hardship factors." },
      { heading: "Statutory Exceptions", content: "Certain penalties have specific statutory exceptions: the failure-to-deposit penalty can be abated if the deposit was made timely but in the wrong manner, and estimated tax penalties may be reduced if you can demonstrate an exception under IRC Section 6654(e).\n\nPenalty abatement can save substantial money — failure-to-pay penalties accrue at 0.5% per month (up to 25%) and failure-to-file penalties accrue at 5% per month (up to 25%), meaning combined penalties can add 50% to the original tax liability." },
    ]),

  // ── BANKRUPTCY ──────────────────────────────────────────
  a("chapter-11-small-business-guide", "Chapter 11 Bankruptcy for Small Business: A Complete Step-by-Step Guide", "bankruptcy",
    "Chapter 11 lets businesses reorganize while continuing operations. Here's how the process works from filing to confirmation.",
    14, "2025-11-08", [
      { heading: "What Is Chapter 11?", content: "Chapter 11 is a federal bankruptcy process that allows businesses to reorganize their debts while continuing to operate. Unlike Chapter 7 (liquidation), Chapter 11 preserves the going-concern value of the business — the employees keep working, customers keep buying, and the business restructures its financial obligations under court supervision.\n\nThe business operates as a \"debtor in possession\" (DIP), meaning the existing management continues to run the company. The court appoints a U.S. Trustee to oversee the case, but day-to-day operations remain under the business owner's control." },
      { heading: "The Automatic Stay", content: "The moment a Chapter 11 petition is filed, the automatic stay goes into effect. This is one of the most powerful tools in bankruptcy: it immediately stops all collection actions, lawsuits, foreclosures, repossessions, wage garnishments, and bank levies.\n\nCreditors who violate the automatic stay can be held in contempt of court and ordered to pay damages, attorney fees, and sanctions. The stay remains in effect throughout the case unless a creditor obtains court permission to lift it.", callout: { type: "info", text: "The automatic stay takes effect at the moment of filing — not when creditors receive notice. Even if a creditor hasn't been notified yet, any collection action after filing violates the stay." } },
      { heading: "Filing Requirements and First-Day Motions", content: "A Chapter 11 filing requires schedules listing all assets, liabilities, income, expenses, contracts, and a statement of financial affairs. First-day motions are filed simultaneously to establish the framework for the case: authority to use cash collateral, pay critical vendors, maintain insurance, continue utility services, and pay employee wages.\n\nThe filing fee for Chapter 11 is $1,738, plus quarterly U.S. Trustee fees based on disbursements. Attorney fees for small business cases typically range from $15,000 to $50,000." },
      { heading: "The Plan Process", content: "The debtor proposes a plan of reorganization that specifies how each class of creditors will be treated. Priority claims (taxes, employee wages) must be paid in full. Secured creditors are typically paid the value of their collateral over time. Unsecured creditors receive what the plan proposes — often a percentage of their claims.\n\nCreditors vote on the plan, and the court confirms it if it meets statutory requirements, including that it's feasible and provides creditors at least as much as they'd receive in Chapter 7 liquidation." },
      { heading: "Timeline and Costs", content: "Traditional Chapter 11 cases typically take 12–24 months from filing to plan confirmation. Post-confirmation payments under the plan may extend 3–5 years. Total costs including attorney fees, filing fees, U.S. Trustee fees, and professional fees can range from $25,000 to $100,000+ for small businesses.\n\nSubchapter V (for businesses with debts under $7.5M) offers a faster, cheaper alternative with a typical timeline of 6–12 months and lower professional fees." },
    ]),

  a("subchapter-v-explained", "Subchapter V Explained: The Simplified Chapter 11 for Businesses Under $7.5M in Debt", "bankruptcy",
    "Subchapter V streamlines Chapter 11 for small businesses with lower costs, faster timelines, and more owner control.",
    9, "2025-10-25", [
      { heading: "What Makes Subchapter V Different", content: "Subchapter V of Chapter 11, created by the Small Business Reorganization Act of 2019, dramatically simplifies the bankruptcy process for businesses with less than $7.5 million in non-contingent, liquidated debt. The key differences: no creditor committee (saving significant costs), a standing trustee who facilitates rather than controls, faster plan filing deadline, and the ability to retain equity even if unsecured creditors vote against the plan.\n\nPerhaps most importantly, the business owner retains ownership without having to provide \"new value\" — a requirement in traditional Chapter 11 that often forced owners to invest new capital." },
      { heading: "Eligibility Requirements", content: "To qualify: the debtor must be a person or entity engaged in commercial or business activities, total non-contingent liquidated debts cannot exceed $7.5 million, and at least 50% of the debt must have arisen from business activities.\n\nSingle asset real estate entities are excluded, and the debtor must elect Subchapter V treatment at the time of filing." },
      { heading: "The Streamlined Process", content: "The debtor must file a plan within 90 days of the petition date (extensions are available for cause). The trustee facilitates negotiations between the debtor and creditors, conducts a status conference within 60 days, and may make distributions under the confirmed plan.\n\nBecause there's no creditor committee, the debtor avoids paying for committee attorneys and financial advisors — which can save $50,000 to $200,000 in a traditional Chapter 11 case." },
      { heading: "Consensual vs. Cramdown Plans", content: "If all creditor classes accept the plan, it's confirmed as a consensual plan. If any class rejects it, the debtor can seek \"cramdown\" confirmation — the court confirms the plan over creditor objections if it meets specific requirements.\n\nIn Subchapter V cramdown, the debtor commits projected disposable income for 3–5 years to plan payments. This is more favorable to debtors than traditional Chapter 11 cramdown, which requires the \"absolute priority rule\" — that equity holders receive nothing unless all senior classes are paid in full." },
    ]),

  a("chapter-7-business-liquidation", "Chapter 7 Business Liquidation: When Closing Is the Best Option", "bankruptcy",
    "Sometimes the best decision is an orderly closure. Here's how Chapter 7 works for business entities.",
    8, "2025-10-12", [
      { heading: "When Chapter 7 Makes Sense", content: "Chapter 7 is appropriate when: the business is no longer viable, debts far exceed the value of assets, continued operation would only deepen losses, and there's no reasonable path to profitability. It's the honest acknowledgment that the business cannot be saved and an orderly wind-down is the best remaining option.\n\nChapter 7 can also be strategic: it eliminates the entity's obligations, stops all collection actions, and provides a defined process for distributing remaining assets to creditors." },
      { heading: "The Trustee Process", content: "A Chapter 7 trustee is appointed to take control of all business assets, liquidate them, and distribute the proceeds to creditors in order of priority: secured creditors (to the extent of their collateral), priority claims (taxes, employee wages), and unsecured creditors.\n\nThe trustee may operate the business briefly if a going-concern sale would yield more than a piecemeal liquidation. This can preserve some jobs and maximize recovery for creditors." },
      { heading: "What Chapter 7 Does NOT Do", content: "A critical misconception: Chapter 7 for a business entity does not discharge any debt. Corporations and LLCs don't receive a discharge in Chapter 7 — they simply cease to exist after assets are distributed. The debts are resolved through the liquidation process, not through a discharge.\n\nMore importantly, personal guarantees survive the corporate Chapter 7. If you personally guaranteed business debts, creditors can still pursue you individually. A separate personal bankruptcy filing may be necessary.", callout: { type: "warning", text: "Personal guarantees survive corporate Chapter 7 bankruptcy. You may need to address personal liability separately through negotiation or personal bankruptcy." } },
      { heading: "Alternatives to Chapter 7", content: "Before filing Chapter 7, consider: Assignment for Benefit of Creditors (faster, cheaper, less public), orderly wind-down without formal filing (if debts are manageable), or converting to Chapter 11 if the business might be saved.\n\nThe choice depends on the nature and volume of debts, whether creditors are actively suing, and whether the automatic stay is needed to halt collection actions." },
    ]),

  a("automatic-stay-explained", "How the Automatic Stay Works: Immediate Protection from Creditors", "bankruptcy",
    "The automatic stay is one of bankruptcy's most powerful tools — instantly stopping lawsuits, levies, and garnishments.",
    7, "2025-09-28", [
      { heading: "What the Automatic Stay Does", content: "The automatic stay, codified at 11 U.S.C. § 362, creates an invisible shield around the debtor and the debtor's property at the moment of filing. It prohibits: commencing or continuing lawsuits, enforcing judgments, creating or enforcing liens, offsetting debts, and any act to collect, assess, or recover a claim that arose before the filing.\n\nThe stay applies to virtually all creditors — banks, vendors, the IRS, state tax agencies, landlords, and lenders. Only a few narrow exceptions exist (certain tax audits, criminal proceedings, domestic support obligations)." },
      { heading: "Enforcing the Stay", content: "Creditors who violate the automatic stay can be sanctioned by the bankruptcy court. Remedies include: actual damages, costs and attorney fees, and in willful violations, punitive damages. Courts take stay violations seriously because the stay is fundamental to the bankruptcy process.\n\nIf a creditor levies your bank account, files a lawsuit, or continues collection calls after you've filed, your attorney should immediately file a motion for contempt and damages." },
      { heading: "Relief from Stay", content: "Creditors can request the court lift the automatic stay for cause — typically when the debtor has no equity in the property and the property isn't necessary for reorganization. In real estate cases, courts may lift the stay if the debtor can't make adequate protection payments to the secured creditor.\n\nThe court balances the creditor's right to protect its collateral against the debtor's need to reorganize. In Chapter 11 cases, courts generally favor keeping the stay in place if the debtor is making progress toward a plan." },
    ]),

  a("debtor-in-possession", "Debtor-in-Possession: How to Keep Running Your Business During Chapter 11", "bankruptcy",
    "As a DIP, you continue managing your business while restructuring debt. Here's what that means in practice.",
    7, "2025-09-15", [
      { heading: "The DIP Concept", content: "In Chapter 11, the business continues to operate as a \"debtor in possession\" — the existing management remains in control of day-to-day operations. There's no trustee running your business. You make operational decisions, manage employees, serve customers, and negotiate with creditors.\n\nHowever, DIP status comes with heightened fiduciary duties. You're now a fiduciary to all creditors and stakeholders, not just equity holders. This means you must act in the best interests of the estate as a whole." },
      { heading: "What You Can and Cannot Do", content: "As DIP, you can continue ordinary course business operations without court approval: paying employees, purchasing inventory, serving customers, and maintaining operations. However, transactions outside the ordinary course — selling significant assets, entering major contracts, borrowing money, or paying pre-petition debts — require court approval.\n\nYou must also file monthly operating reports showing income, expenses, and cash flow, giving the court and creditors visibility into the business's financial performance.", callout: { type: "info", text: "The line between \"ordinary course\" and \"outside ordinary course\" isn't always clear. When in doubt, seek court approval — unauthorized transactions can result in personal liability." } },
      { heading: "DIP Financing", content: "Businesses in Chapter 11 often need additional capital to fund operations during the reorganization. DIP financing is a special type of bankruptcy loan that receives priority over existing creditors — it's \"primed\" above pre-petition debts.\n\nLenders willing to provide DIP financing typically require super-priority status, liens on unencumbered assets, and strict budget compliance. DIP loans are expensive but can be the lifeline that keeps the business operating through the reorganization." },
    ]),

  a("bankruptcy-timeline-costs", "How Long Does Business Bankruptcy Take? Timelines and Costs Explained", "bankruptcy",
    "Real-world timelines and cost ranges for Chapter 7, Chapter 11, and Subchapter V bankruptcy cases.",
    8, "2025-09-01", [
      { heading: "Chapter 7 Timeline", content: "A Chapter 7 business case typically takes 4–6 months from filing to case closure if there are few assets to liquidate. If the trustee needs to sell assets, pursue preference actions, or litigate claims, the case can extend to 12–24 months.\n\nCosts include filing fees ($1,738), attorney fees ($3,000–$10,000 for straightforward cases), and trustee administrative expenses." },
      { heading: "Chapter 11 Timeline", content: "Traditional Chapter 11 cases average 12–24 months from filing to plan confirmation, with plan payments extending 3–5 years after confirmation. Complex cases with significant litigation can take 3+ years.\n\nTotal professional fees often range from $50,000 to $200,000+ for small businesses, including debtor's counsel, financial advisors, and court costs. The expense is the primary reason Chapter 11 has historically been impractical for small businesses." },
      { heading: "Subchapter V Timeline", content: "Subchapter V was designed for speed: the plan must be filed within 90 days, and confirmation typically occurs within 6–12 months. Plan payments extend 3–5 years.\n\nCosts are significantly lower than traditional Chapter 11: attorney fees of $15,000–$40,000, no creditor committee costs, and lower U.S. Trustee fees. The standing trustee's fees are based on plan distributions." },
      { heading: "Factors That Extend Timeline", content: "Several factors can extend any bankruptcy timeline: contested claims, adversary proceedings (lawsuits within the bankruptcy), asset valuation disputes, landlord disputes, IRS or tax agency objections, and debtor non-compliance with reporting requirements.\n\nThe best way to control timeline and costs is to prepare thoroughly before filing, maintain accurate financial records, and comply with all court requirements promptly." },
    ]),

  a("bankruptcy-personal-credit", "Will Business Bankruptcy Affect My Personal Credit? It Depends", "bankruptcy",
    "The impact on your personal credit depends on the business structure, personal guarantees, and type of bankruptcy filed.",
    6, "2025-08-20", [
      { heading: "Corporate vs. Personal Filing", content: "A bankruptcy filing by a corporation or LLC is a separate legal event from the owner's personal credit. The corporate filing does not appear on your personal credit report. However, the indirect effects can be significant: personally guaranteed debts that go into default will appear on your personal credit report.\n\nIf you're a sole proprietor, there's no distinction between business and personal bankruptcy — a sole proprietor files personal bankruptcy." },
      { heading: "The Personal Guarantee Problem", content: "Most business loans, leases, and credit accounts require personal guarantees from the owners. When the business files bankruptcy, these guaranteed debts don't go away — the creditor can pursue the guarantor personally.\n\nIf the creditor charges off the debt and reports it to personal credit bureaus, your credit score can drop 100+ points. Multiple charge-offs from a business failure can make personal credit repair a multi-year process." },
      { heading: "Rebuilding After Business Bankruptcy", content: "If you file personal bankruptcy in addition to business bankruptcy, the filing remains on your personal credit report for 7 years (Chapter 13) or 10 years (Chapter 7). However, credit rebuilding can begin immediately: secured credit cards, credit-builder loans, and timely payment of all new obligations.\n\nMany business owners achieve credit scores of 700+ within 2–3 years of bankruptcy discharge through disciplined credit rebuilding." },
    ]),

  a("assignment-benefit-creditors", "Assignment for Benefit of Creditors: A Faster Alternative to Chapter 7", "bankruptcy",
    "An ABC offers many of the benefits of Chapter 7 with lower costs, faster resolution, and less public scrutiny.",
    7, "2025-08-08", [
      { heading: "What Is an ABC?", content: "An Assignment for Benefit of Creditors (ABC) is a state-law insolvency proceeding where the debtor transfers all assets to an independent third party (the assignee), who liquidates the assets and distributes proceeds to creditors.\n\nThink of it as a private Chapter 7: the result is similar (business assets are sold, creditors receive distributions), but the process is governed by state law rather than federal bankruptcy code." },
      { heading: "Advantages Over Bankruptcy", content: "ABCs offer several advantages: lower costs (no filing fees, no U.S. Trustee fees, no creditor committee), faster resolution (typically 6–12 months), less public scrutiny, more flexibility in asset sales, and often better recoveries for creditors due to lower administrative costs.\n\nThe assignee manages the process efficiently because they're not subject to the extensive court approval requirements of bankruptcy. This often means faster, higher-value asset sales." },
      { heading: "Limitations", content: "ABCs have limitations: no automatic stay (creditors can still sue, levy, or foreclose during the process), no ability to reject contracts or leases, no avoidance powers (can't claw back preferential transfers), and the process varies significantly by state.\n\nABCs work best when: the business has ceased operating, creditors are unlikely to file competing lawsuits, and the primary goal is an orderly wind-down rather than continued operation." },
    ]),

  a("keep-business-open-bankruptcy", "Can I Keep My Business Open During Bankruptcy? What Chapter 11 Actually Allows", "bankruptcy",
    "Yes — Chapter 11 is specifically designed to keep businesses running. Here's what continuing operations looks like.",
    6, "2025-07-25", [
      { heading: "Operating During Chapter 11", content: "Chapter 11 is designed precisely for this purpose — to allow businesses to continue operating while reorganizing debts. The day after filing looks remarkably similar to the day before: employees come to work, customers are served, and orders are filled.\n\nThe key difference is the breathing room. The automatic stay stops all collection actions, giving the business time to stabilize operations without the daily pressure of creditor calls, lawsuits, and bank levies." },
      { heading: "Practical Challenges", content: "While legally permitted, operating during Chapter 11 presents practical challenges: vendors may demand COD terms, customers may worry about warranties or ongoing service, employees may leave for more stable positions, and lenders may impose strict cash budgets.\n\nSuccessful Chapter 11 debtors address these challenges proactively: communicating openly with customers, negotiating critical vendor orders through the court, and retaining key employees through approved retention programs." },
      { heading: "When Courts Intervene", content: "Courts may appoint a Chapter 11 trustee to replace management if there's fraud, dishonesty, incompetence, or gross mismanagement. Courts may also convert the case to Chapter 7 if the business is losing money and has no realistic prospect of reorganization.\n\nThe best way to maintain DIP status and keep operating is to comply with all court requirements, file accurate monthly reports, and demonstrate progress toward a viable reorganization plan." },
    ]),

  a("personal-guarantees-bankruptcy", "Personal Guarantees in Bankruptcy: What Happens to Your Home and Assets", "bankruptcy",
    "Personal guarantees create liability that survives corporate bankruptcy. Here's how to address it.",
    8, "2025-07-12", [
      { heading: "The Guarantee Survives", content: "When a business entity files bankruptcy, the corporate debts are addressed through the bankruptcy proceeding. But personal guarantees are separate obligations of the individual guarantor — they are not discharged by the business bankruptcy.\n\nThis means creditors holding personal guarantees can continue to pursue you personally even after the business has completed its bankruptcy case." },
      { heading: "Protecting Your Home", content: "Whether creditors can reach your home depends on your state's homestead exemption. Texas and Florida offer unlimited homestead protection — creditors cannot force the sale of your primary residence regardless of its value. Other states range from zero homestead exemption (New Jersey) to specific dollar amounts.\n\nIf you're in a low-exemption state, strategic planning before guarantees are called may be essential. An experienced attorney can advise on legitimate asset protection strategies.", callout: { type: "warning", text: "Asset protection planning must be done BEFORE a crisis. Transferring assets when creditors are threatening or lawsuits are pending can be considered fraudulent transfer." } },
      { heading: "Resolution Strategies", content: "Options for addressing personal guarantee liability include: negotiating with creditors (often willing to settle for 40–60% to avoid litigation costs), personal Chapter 7 bankruptcy (if you qualify under the means test), personal Chapter 13 (restructured payments over 3–5 years), or defending against the guarantee on legal grounds (material alteration, fraud, lender misconduct).\n\nThe optimal strategy depends on your total guarantee exposure, exempt vs. non-exempt assets, income level, and whether the guarantees are secured by specific collateral." },
    ]),

  // ── DEBT SETTLEMENT ──────────────────────────────────────────
  a("business-debt-settlement-guide", "Business Debt Settlement: How It Works, What Discounts to Expect, and When It Makes Sense", "debt-settlement",
    "A practical guide to settling business debts for less than owed — including realistic discount ranges by debt type.",
    11, "2025-11-05", [
      { heading: "How Settlement Works", content: "Debt settlement is the process of negotiating with creditors to accept less than the full amount owed as payment in full. The concept is simple: a creditor would rather receive a certain amount now than risk collecting nothing (or less) through expensive and uncertain litigation.\n\nSettlement can involve a single lump-sum payment, a short-term structured payment (3–6 months), or a hybrid approach. The key leverage point is the creditor's assessment of the alternative: if they believe they'll recover less through litigation or bankruptcy, they'll settle." },
      { heading: "Realistic Discount Ranges", content: "Settlement percentages vary significantly by debt type:\n\n• Unsecured business debt (credit cards, lines of credit): 30–60% of balance\n• MCA debt: 40–70% of remaining balance (MCAs are harder to settle because of UCC liens and COJ provisions)\n• SBA loans: 60–85% through the SBA's Offer in Compromise program\n• Vendor/trade debt: 50–80%, depending on the vendor's desire to maintain the relationship\n• Judgment debt: 50–75%, depending on the debtor's collectible assets\n\nThese ranges are guidelines, not guarantees. Actual settlement amounts depend on the creditor's assessment of your ability to pay and the strength of your negotiating position.", callout: { type: "info", text: "The best settlements happen when creditors believe the alternative is worse. A well-documented hardship case showing that settlement is the creditor's best option is essential." } },
      { heading: "The Settlement Process", content: "Step 1: Create a complete debt inventory with balances, interest rates, and guarantee status. Step 2: Assess your financial position and available funds for settlement. Step 3: Prioritize debts based on risk (guaranteed, secured, and tax debts first). Step 4: Make initial contact with creditors or their collection departments. Step 5: Present a settlement offer with supporting documentation. Step 6: Negotiate terms and payment schedule. Step 7: Obtain written settlement agreement before making any payment. Step 8: Complete payment and obtain confirmation of satisfaction.\n\nNever make a settlement payment without a signed written agreement specifying that the payment satisfies the debt in full and that the creditor will release all liens and report the account as settled." },
      { heading: "When Settlement Makes Sense — and When It Doesn't", content: "Settlement works best when: you have access to a lump sum (from asset sales, new investment, or savings), the business is still viable, and bankruptcy would result in less creditor recovery.\n\nSettlement is less effective when: you have no funds to offer, creditors have strong collateral positions, or the debts are guaranteed and the creditor can collect from personal assets. In these situations, bankruptcy may be more appropriate." },
    ]),

  a("negotiate-mca-debt", "How to Negotiate MCA Debt: Replacing Daily Debits with Monthly Payments", "debt-settlement",
    "MCA companies can be negotiated with — but the approach is different from traditional debt negotiation.",
    8, "2025-10-18", [
      { heading: "Why MCA Negotiation Is Different", content: "MCA companies aren't traditional lenders and don't follow traditional collection patterns. They have UCC liens, may have confessions of judgment, and are accustomed to aggressive collection. However, they also know that MCAs have high default rates and that their recovery through litigation is often poor.\n\nThe leverage in MCA negotiation comes from the funder's assessment of alternatives: if litigation will be expensive and recovery uncertain, settlement becomes attractive." },
      { heading: "Opening the Negotiation", content: "Before contacting the MCA company, prepare your position: compile documentation of your financial hardship, calculate total MCA payments already made versus the original advance amount, and determine what you can realistically afford in monthly payments.\n\nThe opening conversation should be direct: you cannot sustain the current daily debits, the alternative is default or bankruptcy (which would yield less recovery), and you're proposing a restructured payment plan that gives the funder a better outcome.", callout: { type: "warning", text: "Be prepared for the MCA company to threaten COJ enforcement or bank levies during negotiations. Having an attorney manage the negotiation reduces this risk." } },
      { heading: "Negotiation Strategies", content: "Effective strategies include: offering a lump-sum settlement at a discount (typically 40–60% of the remaining balance), proposing extended monthly payments at a reduced total payoff, or consolidating multiple MCA positions into a single monthly payment.\n\nIf you've been paying for several months, calculate the total amount paid versus the original advance amount. Often, you've already repaid the principal and are now paying pure profit to the funder — this is a strong argument for settlement." },
    ]),

  a("lump-sum-vs-payment-plans", "Lump-Sum Settlement vs Extended Payment Plans: Which Strategy Wins", "debt-settlement",
    "Understanding when to offer a lump sum versus spreading payments can significantly affect your settlement outcomes.",
    7, "2025-10-05", [
      { heading: "The Lump-Sum Advantage", content: "Creditors strongly prefer lump-sum settlements for a simple reason: certainty. A payment plan can default at any point, while a lump-sum payment closes the file immediately. This preference translates to steeper discounts — lump-sum settlements typically achieve 30–50% of the outstanding balance, while payment plans may only reduce the balance by 10–20%.\n\nHowever, lump-sum settlements require available cash, which distressed businesses often lack." },
      { heading: "Making Payment Plans Work", content: "When a lump sum isn't feasible, structured payment plans can still achieve meaningful reductions. The key is front-loading payments to demonstrate commitment and offering a total repayment amount that's less than the original balance.\n\nA typical structured settlement might look like: 30% of the balance due upon signing, followed by 6 monthly payments totaling 20% more — a total recovery of 50% paid over 7 months. This gives the creditor an immediate substantial payment with a short tail of remaining payments." },
      { heading: "Hybrid Approaches", content: "The most effective settlements often combine approaches: a significant upfront payment (demonstrating good faith and capability) with short-term structured payments. This gives creditors the certainty they want while acknowledging the debtor's cash constraints.\n\nFor businesses with seasonal revenue, payments can be structured around cash flow cycles — larger payments during peak seasons and smaller payments during slow periods." },
    ]),

  a("out-of-court-workouts", "Out-of-Court Workouts: How to Restructure Debt Without Filing Bankruptcy", "debt-settlement",
    "Out-of-court restructuring avoids the cost and stigma of bankruptcy. Here's how to make it work.",
    8, "2025-09-22", [
      { heading: "What Is an Out-of-Court Workout?", content: "An out-of-court workout is a consensual agreement between a debtor and its creditors to restructure debt obligations without filing bankruptcy. It's essentially a private reorganization plan — creditors agree to modified payment terms, reduced balances, or extended maturities in exchange for avoiding the cost and uncertainty of bankruptcy proceedings.\n\nWorkouts are most successful when the business is fundamentally viable but over-leveraged, and when creditors believe they'll recover more through a consensual process than through litigation or bankruptcy." },
      { heading: "Types of Workout Agreements", content: "Composition agreement: All creditors agree to accept a percentage of their claims as payment in full. Extension agreement: Creditors agree to extend payment deadlines and/or reduce interest rates. Combination agreement: Elements of both composition and extension. Standstill agreement: Creditors agree to freeze collection efforts while negotiations proceed.\n\nThese agreements require careful documentation — each creditor must understand what they're accepting and waiving." },
      { heading: "The Holdout Problem", content: "The biggest challenge in out-of-court workouts is the holdout creditor — the one who refuses to participate because they believe they can collect more through individual action. Unlike bankruptcy (where a plan can be forced on dissenting creditors), workouts require unanimous or near-unanimous consent.\n\nThe implied threat of bankruptcy is often the most effective tool against holdouts: if the workout fails and the debtor files Chapter 11, the holdout creditor will likely receive less and wait longer for recovery.", callout: { type: "info", text: "Successful workouts typically require participation from creditors holding 80–90% of total debt. One large holdout creditor can derail the process." } },
    ]),

  a("composition-agreements", "Composition Agreements Explained: Getting All Creditors to Accept Less", "debt-settlement",
    "A composition agreement is a formal arrangement where multiple creditors agree to accept reduced payments simultaneously.",
    6, "2025-09-08", [
      { heading: "How Composition Agreements Work", content: "A composition agreement is a contract between a debtor and its creditors where creditors agree to accept a pro-rata share of available funds as payment in full. The key feature is proportional treatment: each creditor receives the same percentage of their claim.\n\nFor example, if a business offers 40 cents on the dollar, every participating creditor receives 40% of their claim. This equal treatment is what distinguishes compositions from individual settlements." },
      { heading: "Implementation", content: "The debtor prepares a detailed financial disclosure showing total debts, available assets, projected cash flow, and the proposed distribution percentage. An independent third party (accountant or attorney) typically serves as the composition agent — collecting and distributing funds.\n\nCreditors review the financials and either accept or reject the proposal. Once enough creditors accept (typically by amount, not by number), the composition proceeds and participating creditors receive their distribution." },
    ]),

  a("stop-mca-debiting-account", "How to Stop MCA Companies from Debiting Your Bank Account", "debt-settlement",
    "When daily MCA debits are destroying your cash flow, here are your options for stopping the bleeding.",
    7, "2025-08-25", [
      { heading: "Revoking ACH Authorization", content: "You have the right to revoke an ACH authorization at any time by contacting your bank and requesting a \"stop payment\" on recurring ACH debits from the specific originator. Under NACHA (the ACH network operator) rules, your bank must honor this request.\n\nHowever, revoking ACH authorization triggers default under most MCA agreements. The MCA company will immediately pursue other collection remedies — potentially including confession of judgment, UCC lien enforcement, or lawsuit." },
      { heading: "Opening a New Account", content: "A more aggressive approach is opening a new bank account at a different bank and redirecting revenue there. The MCA company will continue attempting to debit the old account, which will fail due to insufficient funds.\n\nThis approach buys time but doesn't resolve the debt. The MCA company will escalate collection efforts, and if they have a confession of judgment, they may be able to levy the new account once they locate it." },
      { heading: "Strategic Approaches", content: "The most effective approach combines blocking ACH debits with immediate negotiation or legal action: block debits, open a new account to protect operating funds, and simultaneously propose a restructured payment plan or prepare a bankruptcy filing.\n\nIf bankruptcy is filed, the automatic stay immediately prohibits all ACH debits — and the MCA company must return any debits processed after the filing date. This combination of ACH revocation plus bankruptcy filing is often the most effective strategy for businesses drowning in MCA debt.", callout: { type: "warning", text: "Simply blocking ACH debits without a plan is dangerous. The MCA company will pursue all available remedies aggressively. Always have a strategy in place before taking action." } },
    ]),

  a("negotiating-with-irs", "Negotiating with the IRS: What Works and What Doesn't", "debt-settlement",
    "The IRS has specific programs and rules. Understanding them is essential to successful tax debt negotiation.",
    8, "2025-08-12", [
      { heading: "Understanding the IRS Perspective", content: "The IRS is not like a private creditor — it doesn't negotiate based on emotion, relationships, or threats. The IRS follows specific procedures codified in the Internal Revenue Manual. Understanding these procedures is the key to successful negotiation.\n\nThe IRS wants to collect the most money it can within the collection statute period. If a settlement or payment plan achieves this goal more efficiently than full collection, the IRS will consider it." },
      { heading: "What Works", content: "Effective IRS negotiation strategies include: complete and accurate financial disclosure (the IRS doesn't negotiate with incomplete information), realistic payment proposals based on IRS-allowed expense standards, well-documented hardship arguments, and professional representation.\n\nTiming matters: negotiating before the IRS files a lien is better than after. Proposing an installment agreement before a Revenue Officer is assigned is easier than after." },
      { heading: "What Doesn't Work", content: "Strategies that fail: ignoring IRS notices (they escalate automatically), making promises you can't keep (defaults result in harsher terms), arguing about fairness (the IRS applies the law, not equity), hiding assets or income (the IRS can access bank records, property records, and third-party information), and using aggressive \"tax resolution\" companies that promise results they can't deliver.", callout: { type: "warning", text: "Beware of \"tax resolution\" firms that guarantee settlements or promise to \"make your tax debt go away.\" No one can guarantee IRS outcomes, and these firms often charge large fees for minimal results." } },
    ]),

  a("settling-with-personal-guarantee", "Settling Debt When You Have a Personal Guarantee: A Strategy Guide", "debt-settlement",
    "Personal guarantees complicate settlement because the creditor has two targets. Here's how to handle it.",
    7, "2025-07-30", [
      { heading: "The Dual Liability Problem", content: "When you've personally guaranteed business debt, the creditor can pursue both the business entity and you individually. This dual collection path gives the creditor more leverage in settlement negotiations — they can apply pressure on either front.\n\nHowever, this works both ways. A settlement that resolves both the business and personal liability simultaneously is attractive to creditors because it closes both files with one agreement." },
      { heading: "Global Settlement Strategy", content: "The most effective approach is a \"global settlement\" that addresses the business obligation and the personal guarantee in a single agreement. The settlement should explicitly release both the entity and the personal guarantor from all liability.\n\nCritical language to include: explicit release of the personal guarantor, agreement to terminate all UCC filings, dismissal of any pending lawsuits against both the entity and guarantor, and agreement not to pursue any deficiency claims." },
      { heading: "Protecting Personal Assets", content: "During settlement negotiations, take steps to protect personal assets: understand your state's exemption laws, document the value of exempt vs. non-exempt assets, and ensure settlement terms don't include additional security against personal property.\n\nNever offer to secure a settlement payment with personal real estate or other assets — this converts unsecured debt to secured debt and worsens your position." },
    ]),

  a("statute-of-limitations-business-debt", "State-by-State Statute of Limitations on Business Debt Collection", "debt-settlement",
    "Every state has a time limit on debt collection lawsuits. Understanding yours could save your business.",
    9, "2025-07-18", [
      { heading: "What Is the Statute of Limitations?", content: "The statute of limitations (SOL) is the time period during which a creditor can file a lawsuit to collect a debt. Once the SOL expires, the debt becomes \"time-barred\" — the creditor can no longer sue to collect it. The clock typically starts when you default (miss a payment).\n\nThe SOL doesn't eliminate the debt — it eliminates the creditor's right to use the court system to collect it. The debt technically still exists, and creditors can still ask you to pay." },
      { heading: "Variations by State and Debt Type", content: "Statutes of limitations vary by state AND by type of obligation:\n\n• Written contracts: 3–10 years depending on the state\n• Open accounts (credit cards): 3–6 years\n• Promissory notes: 3–15 years\n• Oral agreements: 2–6 years\n\nThe applicable SOL is typically determined by the state law specified in the contract or, if none is specified, the state where the contract was executed." },
      { heading: "Restarting the Clock", content: "Making a payment on a time-barred debt or acknowledging the debt in writing can restart the statute of limitations in many states. This is why debt collectors sometimes ask for small \"good faith\" payments — the real purpose is to restart the clock and preserve the right to sue.\n\nBefore making any payment or written acknowledgment of an old debt, determine whether the SOL has expired. If it has, paying even $1 can expose you to a lawsuit for the full balance.", callout: { type: "warning", text: "Never make a payment on old debt without checking the statute of limitations first. Even a small payment can restart the clock and expose you to a lawsuit for the full balance." } },
    ]),

  // ── CASH FLOW & TURNAROUND ──────────────────────────────────
  a("breaking-cash-flow-trap", "Breaking the Cash Flow Trap: Why Borrowing More Makes Everything Worse", "cash-flow",
    "The instinct to borrow your way out of a cash crunch almost always deepens the crisis. Here's why, and what to do instead.",
    9, "2025-11-02", [
      { heading: "The Borrowing Reflex", content: "When cash runs short, the immediate instinct is to find more capital. This is natural and sometimes appropriate. But when borrowing is used to cover operating shortfalls rather than fund growth, it creates a dangerous dynamic: the new debt adds to fixed costs, which further strains cash flow, which triggers the need for even more borrowing.\n\nThis is the cash flow trap: the very solution you reach for — more capital — makes the underlying problem worse. Each round of borrowing adds debt service costs that further reduce available cash for operations." },
      { heading: "Recognizing the Trap", content: "Warning signs that you're in the cash flow trap: using MCA advances to cover payroll, borrowing from one lender to pay another, using personal credit cards for business expenses, falling behind on payroll or sales taxes to preserve cash, and losing vendor terms because of slow payment.\n\nThe mathematical reality is simple: if your revenue can't cover operating costs plus existing debt service, adding more debt (at higher rates) only accelerates the trajectory toward insolvency." },
      { heading: "Breaking Free", content: "Escaping the trap requires addressing the root cause — the gap between revenue and total costs — rather than the symptom (not enough cash). This means:\n\n1. Stabilize: Stop the bleeding by blocking unauthorized debits, opening new accounts, and preserving cash for essential operations.\n2. Analyze: Build a 13-week cash flow forecast to understand exactly where money goes.\n3. Cut: Reduce expenses ruthlessly — renegotiate leases, reduce headcount, eliminate non-essential costs.\n4. Negotiate: Engage creditors about modified payment terms before defaulting.\n5. Restructure: If the business is viable but over-leveraged, pursue formal restructuring (Chapter 11, workout, or ABC)." },
      { heading: "When Borrowing Is Appropriate", content: "Not all borrowing is bad. Borrowing to fund specific revenue-generating activities (inventory for a confirmed order, equipment for a new contract) with a clear return timeline can be appropriate. The test: will this borrowing generate enough incremental revenue to cover its own cost plus a margin of safety?\n\nIf you can't clearly articulate how the borrowed funds will generate enough revenue to repay the loan AND contribute to operating cash flow, the borrowing will make things worse." },
    ]),

  a("13-week-cash-flow-forecast", "The 13-Week Cash Flow Forecast: A Survival Tool Every Struggling Business Needs", "cash-flow",
    "A 13-week cash flow forecast gives you visibility into upcoming shortfalls and is essential for managing a cash crisis.",
    8, "2025-10-20", [
      { heading: "Why 13 Weeks?", content: "A 13-week (one quarter) forecast is the standard tool in turnaround management because it provides a detailed, actionable view of near-term cash flows. It's long enough to identify upcoming problems but short enough to forecast with reasonable accuracy.\n\nUnlike a P&L statement, which records revenue and expenses when they're earned or incurred, a cash flow forecast tracks when money actually enters and leaves your bank account. This distinction is critical: a profitable business can run out of cash if the timing of receipts and payments is misaligned." },
      { heading: "Building Your Forecast", content: "Week 1 starts with today's bank balance. For each subsequent week, project:\n\nCash Inflows: Customer payments (based on actual receivables and payment patterns, not hoped-for sales), other income, and any expected funding.\n\nCash Outflows: Payroll, rent, debt payments (including daily MCA debits), vendor payments, tax deposits, insurance, utilities, and all other disbursements.\n\nEnding Cash = Beginning Cash + Inflows – Outflows. This becomes the beginning cash for the next week.", callout: { type: "info", text: "Be conservative with inflows and aggressive with outflows. A cash forecast is a survival tool — optimism can be fatal. Base projections on actual historical patterns, not sales targets." } },
      { heading: "Using the Forecast", content: "The forecast identifies exactly when shortfalls will occur and how large they'll be. This advance warning allows you to: accelerate collections on specific receivables, delay non-critical payments, negotiate with creditors before defaulting rather than after, plan asset sales or other cash-generating activities, and make informed decisions about which debts to prioritize.\n\nUpdate the forecast weekly, rolling forward one week and adding a new week at the end. Compare actual results to projections and adjust. The accuracy of your forecast improves over time as you calibrate your assumptions." },
    ]),

  a("prioritize-debt-payments", "How to Prioritize Debt Payments When You Can't Pay Everyone", "cash-flow",
    "When cash is limited, paying in the wrong order can expose you to serious legal and financial consequences.",
    8, "2025-10-08", [
      { heading: "The Prioritization Framework", content: "When you can't pay everyone, the order matters enormously. Here's the general priority framework:\n\n1. Payroll taxes and sales taxes (trust fund obligations with personal liability)\n2. Current payroll (employees, not back wages)\n3. Secured creditors threatening immediate action (foreclosure, repossession)\n4. Essential vendor payments (inventory and supplies needed to generate revenue)\n5. Personally guaranteed debts where collection is imminent\n6. Unsecured debts without personal guarantees\n7. Non-essential expenses\n\nThis framework isn't universal — your specific situation may require different priorities." },
      { heading: "Tax Debts Come First", content: "Trust fund taxes (payroll and sales tax) must be the top priority because: they create personal liability that survives bankruptcy, the IRS and states have extraordinary collection powers, and continued non-compliance can trigger criminal referral.\n\nMaking current tax deposits on time while negotiating past-due balances is essential. The IRS will not negotiate if you're continuing to fall behind on current obligations.", callout: { type: "warning", text: "Never pay vendors, lenders, or rent before trust fund taxes. Paying other creditors with money that should go to payroll taxes creates personal liability under the Trust Fund Recovery Penalty." } },
      { heading: "Managing Creditor Expectations", content: "Strategic communication is important: tell creditors what you can pay, when you can pay it, and why you've prioritized payments in this order. Creditors who understand the situation are more likely to work with you than creditors who are surprised by missed payments.\n\nHowever, don't over-communicate. Providing detailed financial information to creditors without legal guidance can weaken your negotiating position." },
    ]),

  a("secured-vs-unsecured-what-to-pay", "Secured vs Unsecured Debt: What to Pay First When Cash Is Tight", "cash-flow",
    "Understanding the difference between secured and unsecured debt is fundamental to effective debt prioritization.",
    7, "2025-09-25", [
      { heading: "Secured Debt: Higher Risk of Immediate Loss", content: "Secured debt is backed by specific collateral — equipment, real estate, vehicles, or inventory. If you default, the creditor can repossess or foreclose on the collateral, potentially shutting down operations if the collateral is essential to the business.\n\nSecured creditors have priority in bankruptcy: they're entitled to the value of their collateral before other creditors receive anything. This makes secured creditors less willing to negotiate because their position is relatively strong." },
      { heading: "Unsecured Debt: More Flexibility, Lower Priority", content: "Unsecured debt is backed only by your promise to pay — there's no specific collateral the creditor can seize. Credit cards, most vendor debt, and many loans are unsecured. In bankruptcy, unsecured creditors receive whatever's left after secured and priority creditors are paid — often very little.\n\nThis weakness is actually your leverage: because unsecured creditors know their recovery in bankruptcy would be poor, they're more willing to negotiate settlements, payment plans, and reduced balances." },
      { heading: "The Personal Guarantee Complication", content: "The secured/unsecured distinction gets complicated when personal guarantees are involved. A business debt may be unsecured at the entity level, but the personal guarantee makes it effectively secured by your personal assets — home equity, savings, vehicles.\n\nWhen prioritizing payments, consider both the business collateral and personal exposure for each debt. A technically unsecured business loan with a personal guarantee and significant personal assets at risk may warrant higher priority than a secured equipment loan where the equipment has minimal value." },
    ]),

  a("emergency-cash-flow-strategies", "Emergency Cash Flow Strategies: Stabilize Before You Negotiate", "cash-flow",
    "Before you can negotiate with creditors, you need to stabilize your cash position. Here's how.",
    7, "2025-09-12", [
      { heading: "Immediate Actions", content: "When cash flow is critical, take these steps immediately: sweep all bank accounts and deposit funds into a clean account not subject to levies or automatic debits, implement a cash-only or pre-payment policy for new orders, issue COD requests to customers with outstanding receivables, and freeze all non-essential spending.\n\nThe goal isn't to solve the problem — it's to stop the deterioration and create stability from which to negotiate." },
      { heading: "Accelerating Cash Inflows", content: "Short-term cash generation strategies: offer early payment discounts (2–3%) to accelerate receivables collection, require deposits on new orders, sell excess or obsolete inventory at discounted prices, monetize unused assets (equipment, vehicles, real estate), and explore short-term asset-based lending against receivables or inventory.\n\nBe creative but realistic: fire sales of critical inventory may generate short-term cash while destroying long-term revenue capacity." },
      { heading: "Reducing Cash Outflows", content: "Cut expenses with surgical precision: renegotiate lease terms (landlords prefer reduced rent to vacant space), reduce workforce to essential staff only, eliminate subscription services and non-critical contracts, and convert fixed costs to variable where possible.\n\nBe particularly aggressive with costs that don't directly generate revenue: reduce office space, switch to VOIP phones, cancel unused software licenses, and negotiate payment terms on insurance premiums." },
    ]),

  a("rebuilding-vendor-relationships", "Rebuilding Vendor Relationships After Default", "cash-flow",
    "Lost vendor trust can be rebuilt, but it requires strategy, patience, and consistent follow-through.",
    6, "2025-08-28", [
      { heading: "Why Vendor Relationships Matter", content: "Vendor credit is one of the most valuable forms of business financing — it's interest-free, relationship-based, and often represents tens of thousands of dollars in de facto financing. Losing vendor terms (being placed on COD or CIA) dramatically increases working capital requirements.\n\nRebuildimg these relationships is essential for long-term business viability. A business that can't obtain trade credit operates at a significant competitive disadvantage." },
      { heading: "The Rebuilding Process", content: "Start by acknowledging the problem directly and honestly. Vendors appreciate candor more than excuses. Present a realistic plan for resuming payments, and offer to start with small orders on a prepaid basis.\n\nAs you make consistent on-time payments, gradually request small increases in order sizes and eventually request COD terms, then short-term credit (net 10, net 15), then standard terms (net 30). This progression typically takes 6–12 months of consistent performance." },
      { heading: "When to Find New Vendors", content: "Some vendor relationships can't be repaired — the damage is too deep or the vendor's policy won't allow renewed credit. In these cases, finding alternative suppliers is necessary. Be transparent with new vendors about your situation: they'll check credit references, and dishonesty discovered later will destroy the new relationship.\n\nConsider offering personal guarantees or letters of credit to new vendors as security while you rebuild your credit history." },
    ]),

  a("rebuild-business-credit", "How to Rebuild Business Credit After Debt Settlement or Bankruptcy", "cash-flow",
    "Credit rebuilding is a process, not an event. Here's a practical timeline and strategy for restoring your business credit.",
    8, "2025-08-15", [
      { heading: "Understanding Business Credit Scores", content: "Business credit scores (Dun & Bradstreet PAYDEX, Experian Intelliscore, Equifax Business Credit Score) are based on different criteria than personal scores. They heavily weight payment history with trade creditors, public records (liens, judgments, bankruptcies), company size and age, and industry risk.\n\nAfter settlement or bankruptcy, these scores will be low. The good news: business credit scores can recover faster than personal scores because they weight recent behavior more heavily than historical events." },
      { heading: "Phase 1: Foundation (Months 1-3)", content: "Obtain your business credit reports from D&B, Experian, and Equifax. Dispute any inaccuracies. Update your business registration, ensure your EIN is current, and file any missing state reports.\n\nApply for vendor accounts that extend credit without requiring a credit check — some office supply companies, fuel cards, and industrial suppliers offer \"starter\" trade credit accounts." },
      { heading: "Phase 2: Building (Months 4-12)", content: "Pay every obligation on time or early — PAYDEX scores reward early payment. Gradually add more trade credit accounts. Apply for a secured business credit card. Maintain low utilization (below 30%) on revolving accounts.\n\nAsk key vendors to report your payment history to the business credit bureaus. Many vendors don't report automatically — a direct request can accelerate your score improvement." },
      { heading: "Phase 3: Growth (Months 12-24)", content: "Apply for unsecured business credit. Consider an SBA microloan to establish a positive bank lending history. Continue adding trade references and maintaining perfect payment history.\n\nBy month 18–24, a business with consistent positive payment history can achieve PAYDEX scores of 80+ (equivalent to net 30 payment), making it eligible for most traditional trade credit and many lending products." },
    ]),

  a("close-vs-fight-framework", "When to Close vs When to Fight: An Honest Framework for Business Owners", "cash-flow",
    "Sometimes fighting isn't worth it. Here's an objective framework for making the hardest decision in business.",
    9, "2025-08-02", [
      { heading: "The Emotional vs. Rational Decision", content: "Business owners are emotionally invested in their businesses. This investment — the years of work, the relationships, the identity tied to the business — makes it extraordinarily difficult to assess viability objectively.\n\nThe hardest truth in business debt is that sometimes the best financial decision is to close. Continuing to operate a non-viable business doesn't just lose money — it deepens personal liability, increases tax exposure, and can transform a manageable debt situation into a catastrophic one." },
      { heading: "The Viability Test", content: "Ask these questions honestly:\n\n1. Can the business generate enough revenue to cover operating costs (excluding debt service)? If no, the business isn't viable regardless of debt restructuring.\n2. Is the market for your product/service growing, stable, or shrinking? Fighting to save a business in a declining market is rarely worthwhile.\n3. How much personal guarantee exposure exists, and is it manageable? If personal liability exceeds your ability to pay or exempt, delay makes it worse.\n4. Do you have the energy and resources for a 2–3 year turnaround? Restructuring is a marathon, not a sprint." },
      { heading: "When to Fight", content: "Fight if: the business is operationally profitable but over-leveraged, the debt was caused by a specific event (pandemic, loss of key client) rather than structural problems, the market opportunity is strong, and restructuring would make the debt service manageable.\n\nChapter 11 or an out-of-court workout can succeed when the underlying business model works and the problem is purely financial." },
      { heading: "When to Close", content: "Close if: the business consistently loses money on an operating basis, the market has fundamentally shifted away from your offerings, personal guarantee exposure is growing and unsecured, continued operation requires ongoing capital infusion from personal resources, or the emotional and physical toll exceeds the potential upside.\n\nClosing strategically — through Chapter 7, ABC, or an orderly wind-down — is far better than running until the money simply runs out.", callout: { type: "info", text: "Closing a business isn't failure — it's a strategic decision. Many successful entrepreneurs closed a business before building one that thrived. The key is managing the closure to minimize personal financial damage." } },
    ]),

  a("cutting-expenses-crisis", "Cutting Expenses in a Crisis Without Killing the Business", "cash-flow",
    "Expense cuts must be surgical, not random. Here's how to reduce costs without destroying revenue capacity.",
    7, "2025-07-20", [
      { heading: "The Surgical Approach", content: "Panic-driven expense cuts — across-the-board reductions, indiscriminate layoffs, eliminating all discretionary spending — often do more harm than good. They can destroy revenue-generating capacity, demoralize remaining staff, and signal to vendors and customers that the business is failing.\n\nInstead, categorize every expense into three buckets: Revenue-generating (directly produces income), Revenue-supporting (enables revenue generation), and Non-essential (everything else). Cut from the bottom up." },
      { heading: "High-Impact, Low-Damage Cuts", content: "Start with expenses that don't affect revenue or customer experience: unused software subscriptions, excessive office space, luxury perks, travel and entertainment, redundant insurance coverage, and overstaffed administrative functions.\n\nThen negotiate reductions: lease modifications (landlords prefer reduced rent to vacancy), insurance rebidding (competitive quotes often yield 10–20% savings), vendor renegotiation (loyalty discounts, volume commitments for better pricing), and utility optimization." },
      { heading: "Workforce Decisions", content: "Payroll is typically the largest expense, and reducing it requires careful thought. Consider: converting full-time positions to part-time or contract, implementing temporary salary reductions (especially for management), eliminating positions through attrition rather than layoffs, and cross-training employees to cover multiple roles.\n\nIf layoffs are necessary, make one significant reduction rather than multiple small ones. Each round of layoffs creates uncertainty and drives voluntary departures of your best employees — the ones who have other options." },
    ]),

  // ── KNOW YOUR RIGHTS ──────────────────────────────────
  a("fdcpa-business-debt", "Fair Debt Collection Practices Act: What Protections Apply to Business Debt", "know-your-rights",
    "The FDCPA primarily protects consumers, but business debtors have protections too. Here's what you need to know.",
    7, "2025-10-30", [
      { heading: "FDCPA and Business Debt", content: "The Fair Debt Collection Practices Act generally applies only to consumer debt, not business debt. However, many debts exist in a gray area — a business credit card with a personal guarantee, a sole proprietorship's obligations, or a personal loan used for business purposes.\n\nWhen a debt has both consumer and business characteristics, the FDCPA may apply. Courts look at the primary purpose of the debt at the time it was incurred to determine whether it's consumer or commercial." },
      { heading: "State-Level Protections", content: "Many states have enacted their own debt collection laws that extend protections to business debtors. States like California, New York, Massachusetts, and Texas have unfair business practices statutes that prohibit abusive collection tactics regardless of whether the debt is consumer or commercial.\n\nThese state laws may prohibit: threatening criminal prosecution for civil debt, contacting the debtor at unreasonable hours, using abusive or profane language, misrepresenting the amount owed, and threatening actions the collector cannot legally take." },
      { heading: "Your Options When Collectors Cross the Line", content: "If a debt collector violates applicable state or federal law, you may have claims for actual damages, statutory damages, and attorney fees. Document every interaction: save letters, record calls (where legally permitted), and keep a log of all communications.\n\nFiling a complaint with the Consumer Financial Protection Bureau (CFPB), your state attorney general, or the Federal Trade Commission creates a regulatory record that can support your claims." },
    ]),

  a("ucc-lien-removal-guide", "UCC Lien Expiration and Removal: A Practical Guide", "know-your-rights",
    "UCC liens can prevent you from obtaining new financing. Here's how to get them removed.",
    7, "2025-10-16", [
      { heading: "UCC-1 Filing Basics", content: "A UCC-1 financing statement gives a creditor a perfected security interest in your business assets. It's filed with the Secretary of State and is publicly searchable. Any potential lender will check for existing UCC filings before extending credit.\n\nUCC filings can be specific (covering particular equipment or receivables) or blanket (covering all present and future assets of the business). MCA companies and alternative lenders typically file blanket liens." },
      { heading: "Automatic Expiration", content: "UCC-1 filings automatically expire 5 years from the date of filing unless the secured party files a continuation statement (UCC-3). If the creditor fails to file a continuation before expiration, the lien lapses and no longer provides any security interest.\n\nCheck the filing date on any UCC-1 against your business — if it's approaching the 5-year mark and the underlying debt has been paid or settled, the creditor may simply let it lapse." },
      { heading: "Demanding Termination", content: "Under UCC Article 9, when the underlying obligation has been satisfied, you can demand that the secured party file a termination statement (UCC-3). The secured party must comply within 20 days of receiving an authenticated demand.\n\nIf the creditor fails to file a termination within 20 days, you may have legal claims for damages — including statutory damages of $500 in many states, plus actual damages caused by the failure to terminate (such as lost financing opportunities).\n\nIn some states, you can file your own termination statement if the secured party is unresponsive. This \"authorized\" termination filing must follow specific procedural requirements." },
    ]),

  a("confession-of-judgment-protections", "States That Banned Confession of Judgment: Where You're Protected", "know-your-rights",
    "Confessions of judgment are banned or restricted in many states. Here's the current landscape.",
    6, "2025-09-30", [
      { heading: "The COJ Problem", content: "A confession of judgment allows a lender to obtain a court judgment against a borrower without notice, a hearing, or any opportunity to present defenses. The lender simply files the pre-signed confession with the court and walks out with an enforceable judgment.\n\nThis power has been widely abused by MCA companies and alternative lenders, who use COJs to freeze bank accounts and seize assets at the first sign of financial difficulty — often before the borrower even knows a judgment has been entered." },
      { heading: "States That Have Acted", content: "New York's landmark 2019 legislation banned enforcement of COJs against out-of-state businesses and imposed new filing requirements for in-state COJs. Several other states have followed:\n\n• Virginia, Maryland, and New Jersey prohibit or severely restrict COJs in commercial lending\n• California doesn't recognize COJs at all\n• Pennsylvania, Ohio, and several other states prohibit or limit COJs in certain types of commercial transactions\n\nThe trend is clearly toward greater protection, but enforcement varies significantly." },
      { heading: "Fighting an Existing COJ", content: "If a COJ judgment has been entered against you or your business, options include: motion to vacate (arguing lack of jurisdiction, fraud, or unconscionability), motion to quash any bank levies or asset seizures, and affirmative claims against the creditor for abuse of process.\n\nTime is critical — once a COJ judgment is entered, the creditor can immediately levy bank accounts and seize assets. Emergency motions must be filed as quickly as possible." },
    ]),

  a("creditors-freeze-bank-account", "Can Creditors Freeze Your Business Bank Account? What to Do When It Happens", "know-your-rights",
    "A bank levy can paralyze your business overnight. Here's how it works and what to do immediately.",
    7, "2025-09-18", [
      { heading: "How Bank Levies Work", content: "A bank levy (also called an account restraint or garnishment) occurs when a creditor with a court judgment serves a restraining notice on your bank. The bank immediately freezes the funds in your account — you cannot make withdrawals, write checks, or use your debit card.\n\nThe frozen funds are held for a statutory period (varies by state, typically 60–90 days for business accounts), during which you can challenge the levy. If unchallenged, the funds are turned over to the creditor." },
      { heading: "Immediate Steps", content: "When your account is levied: open a new account at a different bank immediately and redirect all incoming revenue there, notify your attorney, review the judgment underlying the levy for any grounds to challenge, file an exemption claim if applicable, and consider whether bankruptcy filing (which would lift the levy through the automatic stay) is appropriate.\n\nTime is critical. The longer you wait, the more payroll checks bounce, the more vendor payments fail, and the more customers and employees panic." },
      { heading: "Prevention", content: "If you know a creditor has a judgment against you, take preemptive steps: maintain operating funds in an account that the creditor doesn't know about (at a different bank), keep minimal balances in accounts that appear in public records, and consider whether a preemptive bankruptcy filing or negotiated settlement would prevent the levy.\n\nSome states exempt certain funds from levy — payroll accounts, trust funds, and accounts holding funds of third parties may have protections." },
    ]),

  a("personal-guarantee-defenses", "Personal Guarantee Defenses: Legal Arguments That Can Protect You", "know-your-rights",
    "Personal guarantees aren't always enforceable. Several legal defenses can limit or eliminate your liability.",
    8, "2025-09-05", [
      { heading: "Common Defenses", content: "While personal guarantees are generally enforceable, several defenses may apply:\n\n• Material alteration: If the lender materially modified the loan terms without the guarantor's consent (extended the term, increased the principal, changed the interest rate), the guarantee may be void.\n• Statute of limitations: The SOL on enforcing a guarantee runs from the date of default, not the date the guarantee was signed.\n• Impairment of collateral: If the lender failed to properly protect or maintain collateral, reducing its value, the guarantor's liability may be reduced.\n• Fraud or duress: If the guarantee was obtained through misrepresentation or coercion.\n• Lender misconduct: If the lender acted in bad faith (refusing reasonable workout proposals, accelerating unnecessarily)." },
      { heading: "Waiver Analysis", content: "Most modern guarantees contain extensive waiver provisions — the guarantor waives defenses like notice of default, presentment, demand, protest, and suretyship defenses. These waivers can eliminate many traditional defenses.\n\nHowever, waivers have limits: you can't waive fraud defenses, and waivers obtained through duress or unconscionability may be unenforceable. An experienced attorney can analyze the specific waiver language in your guarantee to identify potential defenses.", callout: { type: "info", text: "Even if defenses are limited, the existence of potential defenses creates settlement leverage. A creditor facing a contested guarantee claim may prefer settling for less rather than litigating." } },
      { heading: "Strategic Considerations", content: "Asserting guarantee defenses is most effective when combined with a realistic settlement proposal. The defense creates uncertainty in the creditor's position, while the settlement offer provides a concrete alternative to expensive litigation.\n\nThe timing of asserting defenses matters: raising them before a judgment is entered (through pre-litigation negotiation or in response to a lawsuit) is far more effective than trying to raise them after a judgment has been entered." },
    ]),

  a("debt-collector-limits", "What Debt Collectors Can and Cannot Legally Do to Your Business", "know-your-rights",
    "Understanding the limits of debt collection helps you respond appropriately and protect your business.",
    6, "2025-08-22", [
      { heading: "What Collectors Can Do", content: "Debt collectors pursuing business debt have broad legal authority: they can call your business during normal business hours, send written demands, report the debt to credit agencies, file lawsuits, obtain judgments, and execute on those judgments through levies, garnishments, and asset seizure.\n\nWith a court judgment, collectors can: freeze and levy bank accounts, garnish receivables, file liens on business property, and in some jurisdictions, seek a turnover order requiring you to surrender assets." },
      { heading: "What Collectors Cannot Do", content: "Even for business debt, collectors cannot: threaten criminal prosecution for civil debt, use physical threats or violence, impersonate law enforcement or government officials, contact third parties about the debt (except to locate you), or misrepresent the amount owed.\n\nMany states also prohibit: contacting you at unreasonable hours, using profane or abusive language, threatening actions they don't intend to take, and continuing to contact you after receiving a written cease-and-desist request." },
      { heading: "Documenting Violations", content: "If you believe a debt collector has crossed legal boundaries, document everything: save all voicemails, letters, and emails; note the date, time, and content of every phone call; and keep a log of all contacts.\n\nThis documentation serves two purposes: it supports regulatory complaints and potential lawsuits against the collector, and it creates leverage in settlement negotiations. A collector facing a counterclaim for collection violations is often more willing to negotiate." },
    ]),

  // ── INDUSTRY GUIDES ──────────────────────────────────
  a("restaurant-debt-crisis", "Restaurant Debt Crisis: The Most Common Financial Traps in Food Service", "industry-guides",
    "Restaurants face unique debt challenges: MCA reliance, thin margins, and equipment obligations that can sink even popular establishments.",
    9, "2025-10-28", [
      { heading: "Why Restaurants Are Vulnerable", content: "The restaurant industry has unique characteristics that make it particularly susceptible to debt problems: razor-thin margins (typically 3–5% net profit), high fixed costs (rent, insurance, licenses), labor-intensive operations (payroll often exceeds 30% of revenue), and seasonal or variable demand.\n\nThis combination means even a modest revenue decline can turn a profitable restaurant into a cash-negative operation. And the instinct to borrow through the downturn — particularly through MCAs — often makes things worse." },
      { heading: "Common Debt Traps", content: "MCA dependence: Restaurants are prime MCA targets because they process high volumes of credit card transactions and need capital quickly. The daily debit structure is devastating for businesses with inherently variable daily revenue.\n\nEquipment leases: Commercial kitchen equipment is expensive, and many restaurants are locked into long-term leases with above-market payments. Walk-in coolers, ovens, POS systems, and HVAC equipment can represent $100,000+ in lease obligations.\n\nSales tax liability: Cash-heavy operations create sales tax compliance challenges. Falling behind on sales tax can trigger license revocation — literally closing your doors.", callout: { type: "warning", text: "States can revoke your food service license for unpaid sales tax. Unlike other debts, sales tax delinquency can literally shut your restaurant down overnight." } },
      { heading: "Restaurant-Specific Solutions", content: "Lease renegotiation: Landlords in competitive restaurant markets would rather reduce rent than face vacancy. Present market comparables and make a realistic proposal.\n\nMCA restructuring: Replace daily ACH debits with monthly payments. If multiple MCAs are stacked, a consolidated restructuring can reduce daily cash drain by 50–70%.\n\nSubchapter V: Small restaurants are ideal candidates for Subchapter V bankruptcy — the streamlined process and lower costs are proportional to restaurant-sized businesses.\n\nAsset preservation: Kitchen equipment and liquor licenses have significant value. A planned restructuring preserves these assets, while an uncontrolled shutdown destroys them." },
    ]),

  a("construction-contractor-debt", "Construction & Contractor Debt: Managing Cash Flow in a Project-Based Business", "industry-guides",
    "Construction's project-based cash flow creates feast-or-famine cycles. Here's how to manage debt in this environment.",
    8, "2025-10-15", [
      { heading: "The Project Cash Flow Problem", content: "Construction businesses face a unique cash flow challenge: expenses are front-loaded (materials, labor, equipment mobilization), but revenue arrives in stages (progress billings, retainage holdbacks). This mismatch creates periodic cash shortfalls even for profitable projects.\n\nRetainage — the 5–10% holdback on each progress billing — can represent hundreds of thousands of dollars tied up for months after project completion. This trapped capital is a major driver of construction company borrowing." },
      { heading: "Equipment Financing Challenges", content: "Heavy construction equipment is expensive, depreciates quickly, and is essential to generating revenue. Equipment loans and leases represent significant fixed costs that continue regardless of project pipeline.\n\nWhen project volume drops, equipment sits idle but payments continue. The equipment's market value often drops below the loan balance, creating negative equity — you owe more than the equipment is worth." },
      { heading: "Protection Strategies", content: "Mechanic's lien rights are your most powerful collection tool. File preliminary notices on every project, enforce lien rights aggressively, and don't let receivables age beyond your state's lien filing deadline.\n\nBonding requirements complicate restructuring: surety companies monitor financial condition and can refuse to bond new projects if your financials deteriorate. Address debt problems early, before they affect your bonding capacity.\n\nConsider joint ventures or subcontracting to maintain project flow without the overhead of full project ownership during financial recovery." },
    ]),

  a("medical-dental-practice-debt", "Medical & Dental Practice Debt: Unique Challenges and Solutions", "industry-guides",
    "Healthcare practices have valuable revenue streams but complex debt structures involving equipment, practice acquisition, and insurance dependencies.",
    8, "2025-09-28", [
      { heading: "Practice-Specific Challenges", content: "Medical and dental practices carry unique debt burdens: practice acquisition loans (often $500,000+), expensive specialized equipment (imaging systems, dental chairs, surgical equipment), build-out and lease obligations for specialized office space, and staffing costs that can't be quickly reduced without affecting patient care.\n\nRevenue is complicated by insurance reimbursement delays (30–120 days), declining reimbursement rates, and the complexity of medical billing." },
      { heading: "The Reimbursement Problem", content: "Insurance reimbursement delays create a structural cash flow gap: you provide services today and get paid 60–120 days later. Revenue-based financing against expected reimbursements can help bridge this gap, but at high cost.\n\nChanges in insurance contracts, coding requirements, or reimbursement rates can create sudden revenue drops that are difficult to reverse quickly." },
      { heading: "Restructuring vs. Practice Sale", content: "Medical practices often have strong underlying value — a reliable patient base, insurance contracts, and specialized equipment. This value creates restructuring options that other businesses don't have.\n\nConsider: selling the practice as a going concern to a larger practice or management group (often at a premium to asset value), bringing in a partner to inject capital and share overhead, or restructuring through Subchapter V while maintaining patient care.\n\nPractice sale proceeds can satisfy most or all debt obligations while allowing the practitioner to continue practicing as an employee of the acquiring entity." },
    ]),

  a("trucking-company-debt", "Trucking Company Debt: Equipment Loans, Fuel Costs, and MCA Traps", "industry-guides",
    "Trucking companies face equipment depreciation, volatile fuel costs, and predatory MCA lending targeting the industry.",
    7, "2025-09-15", [
      { heading: "Equipment Loan Challenges", content: "Trucks and trailers are essential revenue-generating assets, but they depreciate rapidly — a new Class 8 truck loses 30–40% of its value in the first two years. This creates negative equity quickly: a 5-year equipment loan on a $180,000 truck may have a $120,000 balance while the truck is worth $100,000.\n\nDefault means repossession, but surrendering the truck means you can't haul — and you still owe the deficiency balance." },
      { heading: "Fuel and Operating Costs", content: "Fuel represents 25–35% of a trucking company's operating costs, and fuel price volatility can quickly erode margins. Fuel cards and fleet fueling accounts can create additional debt when payments are delayed.\n\nInsurance costs, DOT compliance expenses, and maintenance create additional fixed cost pressure. A trucking company with 10 trucks and 10 drivers has significant fixed costs regardless of utilization." },
      { heading: "Restructuring Strategies", content: "For overleveraged trucking companies: negotiate with equipment lenders to extend terms or reduce payments, strategically surrender underwater trucks (those with high mileage and low value relative to the loan balance), maintain essential operating authority and insurance, and focus on the most profitable lanes and customers.\n\nChapter 11 can be effective for trucking companies because the automatic stay prevents equipment repossession while you develop a reorganization plan that retains essential trucks and surrenders others." },
    ]),

  a("retail-ecommerce-debt", "Retail & E-commerce Debt: When Inventory Financing Backfires", "industry-guides",
    "Retail businesses face unique challenges when inventory financing, seasonal fluctuations, and online competition create debt problems.",
    7, "2025-09-02", [
      { heading: "Inventory as Asset and Liability", content: "Inventory is simultaneously a retail business's most important asset and a potential source of significant loss. Inventory financing (including floor plans, purchase order financing, and lines of credit) ties up capital in physical goods that may not sell.\n\nSeasonal businesses face amplified risk: they borrow heavily to stock inventory for peak season, and if sales disappoint, they're left with depreciating inventory and debt to service." },
      { heading: "E-commerce Specific Risks", content: "Online retailers face additional challenges: payment processor reserves (holdbacks of 5–10% of sales for 180 days), marketplace payment delays (Amazon pays every 14 days; chargebacks and returns can further delay payment), and the constant pressure to invest in advertising and marketing to maintain visibility.\n\nMCA companies aggressively target e-commerce businesses because they can verify revenue through marketplace seller accounts and payment processor data." },
      { heading: "Recovery Strategies", content: "Inventory liquidation at a discount converts aging inventory to cash immediately. While the margin is lower, the cash flow benefit can be significant. Consider liquidation channels: online marketplaces, liquidation companies, or bulk sales to discount retailers.\n\nNegotiate with payment processors about reserve releases — if your chargeback rate is low, you may be able to reduce or eliminate the holdback. For brick-and-mortar retailers, aggressive lease renegotiation is essential: retail landlords in most markets have high vacancy rates and will negotiate rather than lose a tenant." },
    ]),

  a("professional-services-debt", "Professional Services Firm Debt: Managing Overhead When Revenue Drops", "industry-guides",
    "Professional services firms with high overhead and client concentration face unique risks when key relationships change.",
    7, "2025-08-20", [
      { heading: "The Client Concentration Risk", content: "Many professional services firms derive 40–60% of revenue from 1–3 key clients. Losing a single major client can create an immediate cash flow crisis — the overhead (office space, staff, technology) was sized for the higher revenue level and can't be reduced quickly.\n\nClient concentration also creates leverage risk: if you borrowed against the revenue from a key client and that client leaves, you have debt payments but insufficient revenue to cover them." },
      { heading: "Overhead Management", content: "Professional services firms typically have high fixed costs relative to revenue: office leases, professional staff salaries, technology and licensing fees, and insurance. These costs can represent 70–80% of revenue, leaving thin margins for debt service.\n\nWhen revenue drops, these fixed costs become a crushing burden. The key is converting fixed costs to variable wherever possible: subleasing excess office space, using contract professionals instead of full-time employees, and negotiating usage-based pricing for technology services." },
      { heading: "Partner and Ownership Issues", content: "Multi-partner firms face additional complexity: partner disputes, buyout obligations, and disagreements about strategy can compound financial distress. A partner departure during a debt crisis can trigger loan covenants, reduce revenue further, and create additional buyout obligations.\n\nAddress partner issues directly and early: renegotiate partnership agreements, defer buyout payments, and align all partners on a recovery strategy. If alignment isn't possible, a managed dissolution may be preferable to ongoing conflict." },
    ]),
];

export const getArticlesByCategory = (cat: CategoryId) =>
  articles.filter((a) => a.category === cat);

export const getFeaturedArticles = () =>
  articles.filter((a) => a.featured);

export const getMostReadArticles = () =>
  articles.slice(0, 8);

export const getRelatedArticles = (current: Article): Article[] =>
  articles
    .filter((a) => a.category === current.category && a.slug !== current.slug)
    .slice(0, 3);
